            const data = loadFromSlot(slotIndex);
            if (data) {
                // 버전 검증 로직 추가
                if (data.version !== APP_VERSION) {
                    actions.showToast(`Load Failed: Version mismatch. (Save: v${data.version || '0.1.36'}, App: v${APP_VERSION})`);
                    return;
                }
                setLoadConfirm({ isOpen: true, data, index: slotIndex });
            }
