import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { useGame } from '../context/GameContext';
import { getMusicUrl } from '../utils';

/**
 * AudioManager
 * Web Audio API(AudioContext)를 사용하여 배경음을 관리합니다.
 * 던전 진입/종료 등 게임 상태 변화에 따라 음악을 즉시 중단하고 교체합니다.
 */
const AudioManager: React.FC = () => {
    const { state } = useGame();
    const audioSettings = state.settings.audio;
    const activeDungeonId = state.activeManualDungeon?.dungeonId;

    const contextRef = useRef<AudioContext | null>(null);
    const gainNodeRef = useRef<GainNode | null>(null);
    const sourceRef = useRef<AudioBufferSourceNode | null>(null);
    const bufferCache = useRef<Map<string, AudioBuffer>>(new Map());
    const currentTrackName = useRef<string | null>(null);
    const [isLoaded, setIsLoaded] = useState(false);

    // 1. 현재 상황에 맞는 트랙 결정
    const targetTrackName = useMemo(() => {
        if (activeDungeonId === 'dungeon_t1_sewers') {
            return 'dungeon_track_01.mp3';
        }
        return 'track_01.mp3';
    }, [activeDungeonId]);

    // 2. 오디오 시스템 초기화
    useEffect(() => {
        const AudioCtx = window.AudioContext || (window as any).webkitAudioContext;
        const ctx = new AudioCtx();
        const gainNode = ctx.createGain();
        gainNode.connect(ctx.destination);

        contextRef.current = ctx;
        gainNodeRef.current = gainNode;

        if ('mediaSession' in navigator) {
            navigator.mediaSession.metadata = null;
            navigator.mediaSession.playbackState = 'none';
        }

        setIsLoaded(true);

        return () => {
            stopPlayback(0); // 즉시 정지
            if (contextRef.current) {
                contextRef.current.close();
            }
        };
    }, []);

    /**
     * 재생 중지 로직
     * @param fadeTime 페이드 아웃 시간 (초)
     */
    const stopPlayback = useCallback((fadeTime: number = 0.3) => {
        const gainNode = gainNodeRef.current;
        const source = sourceRef.current;
        const ctx = contextRef.current;

        if (source && gainNode && ctx) {
            // 현재 볼륨에서 0으로 페이드 아웃
            const currentGain = gainNode.gain.value;
            gainNode.gain.cancelScheduledValues(ctx.currentTime);
            gainNode.gain.setValueAtTime(currentGain, ctx.currentTime);
            gainNode.gain.linearRampToValueAtTime(0, ctx.currentTime + fadeTime);

            // 페이드 아웃 완료 후 정지 및 정리
            setTimeout(() => {
                try {
                    source.stop();
                } catch (e) {}
                source.disconnect();
                if (sourceRef.current === source) {
                    sourceRef.current = null;
                    currentTrackName.current = null;
                }
            }, fadeTime * 1000 + 50);
        } else if (source) {
            // 노드가 없으면 즉시 정지
            try { source.stop(); } catch(e) {}
            source.disconnect();
            sourceRef.current = null;
            currentTrackName.current = null;
        }
    }, []);

    /**
     * 트랙 재생 시작 로직
     */
    const startPlayback = useCallback(async (trackName: string) => {
        const ctx = contextRef.current;
        const gainNode = gainNodeRef.current;
        if (!ctx || !gainNode) return;

        // 동일 트랙이 이미 재생 중이면 무시
        if (currentTrackName.current === trackName && sourceRef.current) return;

        // [중요] 새로운 음악 로드 전 기존 음악 정지
        stopPlayback(0.2); 

        try {
            let buffer = bufferCache.current.get(trackName);

            if (!buffer) {
                const response = await fetch(getMusicUrl(trackName));
                const arrayBuffer = await response.arrayBuffer();
                buffer = await ctx.decodeAudioData(arrayBuffer);
                bufferCache.current.set(trackName, buffer);
            }

            // 새로운 트랙이 준비되는 동안 상황이 바뀌었는지 체크
            if (targetTrackName !== trackName) return;

            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.loop = true;
            source.connect(gainNode);

            // 볼륨 복구 및 시작
            const effectiveVolume = audioSettings.masterVolume * audioSettings.musicVolume;
            gainNode.gain.cancelScheduledValues(ctx.currentTime);
            gainNode.gain.setValueAtTime(0, ctx.currentTime);
            gainNode.gain.linearRampToValueAtTime(effectiveVolume, ctx.currentTime + 0.5);

            if (ctx.state === 'suspended') {
                await ctx.resume();
            }

            source.start(0);
            sourceRef.current = source;
            currentTrackName.current = trackName;
        } catch (e) {
            console.debug(`BGM [${trackName}] 전환 실패:`, e);
        }
    }, [targetTrackName, audioSettings.masterVolume, audioSettings.musicVolume, stopPlayback]);

    // 3. 트랙 변경 및 볼륨 설정 동기화
    useEffect(() => {
        if (!isLoaded) return;

        const gainNode = gainNodeRef.current;
        const ctx = contextRef.current;
        if (!gainNode || !ctx) return;

        const shouldPlay = audioSettings.masterEnabled && audioSettings.musicEnabled;

        if (shouldPlay) {
            // 트랙이 다르거나 재생 중이 아니면 시작 (내부에서 기존 정지 처리)
            if (currentTrackName.current !== targetTrackName || !sourceRef.current) {
                startPlayback(targetTrackName);
            } else {
                // 동일 트랙 재생 중이면 볼륨만 업데이트
                const effectiveVolume = audioSettings.masterVolume * audioSettings.musicVolume;
                gainNode.gain.setTargetAtTime(effectiveVolume, ctx.currentTime, 0.1);
            }
        } else {
            // 비활성화 시 페이드 아웃하며 정지
            stopPlayback(0.5);
        }
    }, [isLoaded, targetTrackName, audioSettings.masterVolume, audioSettings.musicVolume, audioSettings.masterEnabled, audioSettings.musicEnabled, startPlayback, stopPlayback]);

    // 4. 브라우저 Autoplay 정책 대응
    useEffect(() => {
        const handleInteraction = () => {
            if (contextRef.current && contextRef.current.state === 'suspended') {
                contextRef.current.resume();
            }
            const shouldPlay = audioSettings.masterEnabled && audioSettings.musicEnabled;
            if (shouldPlay && !sourceRef.current) {
                startPlayback(targetTrackName);
            }
        };

        window.addEventListener('mousedown', handleInteraction, { once: true });
        window.addEventListener('touchstart', handleInteraction, { once: true });
        return () => {
            window.removeEventListener('mousedown', handleInteraction);
            window.removeEventListener('touchstart', handleInteraction);
        };
    }, [audioSettings.masterEnabled, audioSettings.musicEnabled, targetTrackName, startPlayback]);

    return null;
};

export default AudioManager;

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { useGame } from '../context/GameContext';
import { getMusicUrl, getAudioUrl } from '../utils';

/**
 * AudioManager
 * Web Audio API(AudioContext)를 사용하여 배경음(BGM)과 효과음(SFX)을 통합 관리합니다.
 */
const AudioManager: React.FC = () => {
    const { state } = useGame();
    const audioSettings = state.settings.audio;
    const activeDungeonId = state.activeManualDungeon?.dungeonId;

    const contextRef = useRef<AudioContext | null>(null);
    const bgmGainRef = useRef<GainNode | null>(null);
    const sfxGainRef = useRef<GainNode | null>(null);
    const bgmSourceRef = useRef<AudioBufferSourceNode | null>(null);

    const bgmCache = useRef<Map<string, AudioBuffer>>(new Map());
    const sfxCache = useRef<Map<string, AudioBuffer>>(new Map());
    const currentTrackName = useRef<string | null>(null);
    const [isLoaded, setIsLoaded] = useState(false);

    // 1. 현재 상황에 맞는 BGM 트랙 결정
    const targetTrackName = useMemo(() => {
        if (activeDungeonId === 'dungeon_t1_sewers') {
            return 'dungeon_track_01.mp3';
        }
        return 'track_01.mp3';
    }, [activeDungeonId]);

    // 2. 오디오 시스템 초기화
    useEffect(() => {
        const AudioCtx = window.AudioContext || (window as any).webkitAudioContext;
        const ctx = new AudioCtx();

        const bgmGain = ctx.createGain();
        const sfxGain = ctx.createGain();

        bgmGain.connect(ctx.destination);
        sfxGain.connect(ctx.destination);

        contextRef.current = ctx;
        bgmGainRef.current = bgmGain;
        sfxGainRef.current = sfxGain;

        if ('mediaSession' in navigator) {
            navigator.mediaSession.metadata = null;
            navigator.mediaSession.playbackState = 'none';
        }

        setIsLoaded(true);

        return () => {
            stopBgm(0);
            if (contextRef.current) {
                contextRef.current.close();
            }
        };
    }, []);

    /**
     * BGM 중지 로직
     */
    const stopBgm = useCallback((fadeTime: number = 0.3) => {
        const gainNode = bgmGainRef.current;
        const source = bgmSourceRef.current;
        const ctx = contextRef.current;

        if (source && gainNode && ctx) {
            const currentGain = gainNode.gain.value;
            gainNode.gain.cancelScheduledValues(ctx.currentTime);
            gainNode.gain.setValueAtTime(currentGain, ctx.currentTime);
            gainNode.gain.linearRampToValueAtTime(0, ctx.currentTime + fadeTime);

            setTimeout(() => {
                try { source.stop(); } catch (e) {}
                source.disconnect();
                if (bgmSourceRef.current === source) {
                    bgmSourceRef.current = null;
                    currentTrackName.current = null;
                }
            }, fadeTime * 1000 + 50);
        } else if (source) {
            try { source.stop(); } catch(e) {}
            source.disconnect();
            bgmSourceRef.current = null;
            currentTrackName.current = null;
        }
    }, []);

    /**
     * BGM 재생 시작
     */
    const startBgm = useCallback(async (trackName: string) => {
        const ctx = contextRef.current;
        const gainNode = bgmGainRef.current;
        if (!ctx || !gainNode) return;

        if (currentTrackName.current === trackName && bgmSourceRef.current) return;

        stopBgm(0.2); 

        try {
            let buffer = bgmCache.current.get(trackName);
            if (!buffer) {
                const response = await fetch(getMusicUrl(trackName));
                const arrayBuffer = await response.arrayBuffer();
                buffer = await ctx.decodeAudioData(arrayBuffer);
                bgmCache.current.set(trackName, buffer);
            }

            if (targetTrackName !== trackName) return;

            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.loop = true;
            source.connect(gainNode);

            const effectiveVolume = audioSettings.masterVolume * audioSettings.musicVolume;
            gainNode.gain.cancelScheduledValues(ctx.currentTime);
            gainNode.gain.setValueAtTime(0, ctx.currentTime);
            gainNode.gain.linearRampToValueAtTime(effectiveVolume, ctx.currentTime + 0.5);

            if (ctx.state === 'suspended') await ctx.resume();

            source.start(0);
            bgmSourceRef.current = source;
            currentTrackName.current = trackName;
        } catch (e) {
            console.debug(`BGM [${trackName}] play failed:`, e);
        }
    }, [targetTrackName, audioSettings.masterVolume, audioSettings.musicVolume, stopBgm]);

    /**
     * SFX 재생 로직
     */
    const playSfx = useCallback(async (filename: string) => {
        const ctx = contextRef.current;
        const gainNode = sfxGainRef.current;
        if (!ctx || !gainNode || !audioSettings.masterEnabled || !audioSettings.sfxEnabled) return;

        try {
            let buffer = sfxCache.current.get(filename);
            if (!buffer) {
                const response = await fetch(getAudioUrl(filename));
                const arrayBuffer = await response.arrayBuffer();
                buffer = await ctx.decodeAudioData(arrayBuffer);
                sfxCache.current.set(filename, buffer);
            }

            if (ctx.state === 'suspended') await ctx.resume();

            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.connect(gainNode);
            source.start(0);
        } catch (e) {
            console.debug(`SFX [${filename}] play failed:`, e);
        }
    }, [audioSettings.masterEnabled, audioSettings.sfxEnabled]);

    // BGM 설정 업데이트
    useEffect(() => {
        if (!isLoaded) return;
        const gainNode = bgmGainRef.current;
        const ctx = contextRef.current;
        if (!gainNode || !ctx) return;

        const shouldPlay = audioSettings.masterEnabled && audioSettings.musicEnabled;
        if (shouldPlay) {
            if (currentTrackName.current !== targetTrackName || !bgmSourceRef.current) {
                startBgm(targetTrackName);
            } else {
                const effectiveVolume = audioSettings.masterVolume * audioSettings.musicVolume;
                gainNode.gain.setTargetAtTime(effectiveVolume, ctx.currentTime, 0.1);
            }
        } else {
            stopBgm(0.5);
        }
    }, [isLoaded, targetTrackName, audioSettings.masterVolume, audioSettings.musicVolume, audioSettings.masterEnabled, audioSettings.musicEnabled, startBgm, stopBgm]);

    // SFX 볼륨 업데이트
    useEffect(() => {
        if (!isLoaded) return;
        const gainNode = sfxGainRef.current;
        const ctx = contextRef.current;
        if (gainNode && ctx) {
            const effectiveVolume = audioSettings.masterVolume * audioSettings.sfxVolume;
            gainNode.gain.setTargetAtTime(effectiveVolume, ctx.currentTime, 0.05);
        }
    }, [isLoaded, audioSettings.masterVolume, audioSettings.sfxVolume]);

    // SFX 이벤트 리스너
    useEffect(() => {
        const handleSfxRequest = (e: any) => {
            if (e.detail?.file) {
                playSfx(e.detail.file);
            }
        };
        window.addEventListener('play-sfx', handleSfxRequest);
        return () => window.removeEventListener('play-sfx', handleSfxRequest);
    }, [playSfx]);

    // 브라우저 Autoplay 정책 대응
    useEffect(() => {
        const handleInteraction = () => {
            if (contextRef.current && contextRef.current.state === 'suspended') {
                contextRef.current.resume();
            }
        };
        window.addEventListener('mousedown', handleInteraction, { once: true });
        window.addEventListener('touchstart', handleInteraction, { once: true });
        return () => {
            window.removeEventListener('mousedown', handleInteraction);
            window.removeEventListener('touchstart', handleInteraction);
        };
    }, []);

    return null;
};

export default AudioManager;

