import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { useGame } from '../context/GameContext';
import { getMusicUrl, getAudioUrl } from '../utils';

/**
 * AudioManager
 * Web Audio API(AudioContext)를 사용하여 배경음(BGM)과 효과음(SFX)을 통합 관리합니다.
 */
const AudioManager: React.FC = () => {
    const { state } = useGame();
    const audioSettings = state.settings.audio;
    const activeDungeonId = state.activeManualDungeon?.dungeonId;

    const contextRef = useRef<AudioContext | null>(null);
    const bgmGainRef = useRef<GainNode | null>(null);
    const sfxGainRef = useRef<GainNode | null>(null);
    const bgmSourceRef = useRef<AudioBufferSourceNode | null>(null);

    const bgmCache = useRef<Map<string, AudioBuffer>>(new Map());
    const sfxCache = useRef<Map<string, AudioBuffer>>(new Map());
    const currentTrackName = useRef<string | null>(null);
    const [isLoaded, setIsLoaded] = useState(false);

    // 1. 현재 상황에 맞는 BGM 트랙 결정
    const targetTrackName = useMemo(() => {
        if (activeDungeonId === 'dungeon_t1_sewers') {
            return 'dungeon_track_01.mp3';
        }
        return 'track_01.mp3';
    }, [activeDungeonId]);

    // 2. 오디오 시스템 초기화
    useEffect(() => {
        const AudioCtx = window.AudioContext || (window as any).webkitAudioContext;
        const ctx = new AudioCtx();

        const bgmGain = ctx.createGain();
        const sfxGain = ctx.createGain();

        bgmGain.connect(ctx.destination);
        sfxGain.connect(ctx.destination);

        contextRef.current = ctx;
        bgmGainRef.current = bgmGain;
        sfxGainRef.current = sfxGain;

        if ('mediaSession' in navigator) {
            navigator.mediaSession.metadata = null;
            navigator.mediaSession.playbackState = 'none';
        }

        setIsLoaded(true);

        return () => {
            stopBgm(0);
            if (contextRef.current) {
                contextRef.current.close();
            }
        };
    }, []);

    /**
     * BGM 중지 로직
     */
    const stopBgm = useCallback((fadeTime: number = 0.3) => {
        const gainNode = bgmGainRef.current;
        const source = bgmSourceRef.current;
        const ctx = contextRef.current;

        if (source && gainNode && ctx) {
            const currentGain = gainNode.gain.value;
            gainNode.gain.cancelScheduledValues(ctx.currentTime);
            gainNode.gain.setValueAtTime(currentGain, ctx.currentTime);
            gainNode.gain.linearRampToValueAtTime(0, ctx.currentTime + fadeTime);

            setTimeout(() => {
                try { source.stop(); } catch (e) {}
                source.disconnect();
                if (bgmSourceRef.current === source) {
                    bgmSourceRef.current = null;
                    currentTrackName.current = null;
                }
            }, fadeTime * 1000 + 50);
        } else if (source) {
            try { source.stop(); } catch(e) {}
            source.disconnect();
            bgmSourceRef.current = null;
            currentTrackName.current = null;
        }
    }, []);

    /**
     * BGM 재생 시작
     */
    const startBgm = useCallback(async (trackName: string) => {
        const ctx = contextRef.current;
        const gainNode = bgmGainRef.current;
        if (!ctx || !gainNode) return;

        if (currentTrackName.current === trackName && bgmSourceRef.current) return;

        stopBgm(0.2); 

        try {
            let buffer = bgmCache.current.get(trackName);
            if (!buffer) {
                const url = getMusicUrl(trackName);
                const response = await fetch(url);

                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status} at ${url}`);
                }

                const contentType = response.headers.get('content-type');
                if (contentType && contentType.includes('text/html')) {
                    throw new Error(`Invalid content type: received HTML instead of audio at ${url}`);
                }

                const arrayBuffer = await response.arrayBuffer();
                buffer = await ctx.decodeAudioData(arrayBuffer);
                bgmCache.current.set(trackName, buffer);
            }

            if (targetTrackName !== trackName) return;

            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.loop = true;
            source.connect(gainNode);

            const effectiveVolume = audioSettings.masterVolume * audioSettings.musicVolume;
            gainNode.gain.cancelScheduledValues(ctx.currentTime);
            gainNode.gain.setValueAtTime(0, ctx.currentTime);
            gainNode.gain.linearRampToValueAtTime(effectiveVolume, ctx.currentTime + 0.5);

            if (ctx.state === 'suspended') await ctx.resume();

            source.start(0);
            bgmSourceRef.current = source;
            currentTrackName.current = trackName;
        } catch (e) {
            console.warn(`[Audio] BGM [${trackName}] play failed:`, e);
        }
    }, [targetTrackName, audioSettings.masterVolume, audioSettings.musicVolume, stopBgm]);

    /**
     * SFX 재생 로직
     */
    const playSfx = useCallback(async (filename: string) => {
        const ctx = contextRef.current;
        const gainNode = sfxGainRef.current;
        if (!ctx || !gainNode) return;

        // 설정 확인
        if (!audioSettings.masterEnabled || !audioSettings.sfxEnabled) {
            console.debug(`[Audio] SFX [${filename}] skip (Muted)`);
            return;
        }

        try {
            let buffer = sfxCache.current.get(filename);
            if (!buffer) {
                const url = getAudioUrl(filename);
                console.debug(`[Audio] Fetching SFX: ${url}`);
                const response = await fetch(url);

                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status} for ${filename}`);
                }

                const contentType = response.headers.get('content-type');
                if (contentType && contentType.includes('text/html')) {
                    throw new Error(`Invalid content type: received HTML instead of audio for ${filename}. Check if file exists at URL.`);
                }

                const arrayBuffer = await response.arrayBuffer();
                buffer = await ctx.decodeAudioData(arrayBuffer);
                sfxCache.current.set(filename, buffer);
            }

            if (ctx.state === 'suspended') {
                await ctx.resume();
            }

            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.connect(gainNode);
            source.start(0);
            console.debug(`[Audio] Playing SFX: ${filename}`);
        } catch (e) {
            console.error(`[Audio] SFX [${filename}] error:`, e);
        }
    }, [audioSettings.masterEnabled, audioSettings.sfxEnabled]);

    // BGM 설정 업데이트
    useEffect(() => {
        if (!isLoaded) return;
        const gainNode = bgmGainRef.current;
        const ctx = contextRef.current;
        if (!gainNode || !ctx) return;

        const shouldPlay = audioSettings.masterEnabled && audioSettings.musicEnabled;
        if (shouldPlay) {
            if (currentTrackName.current !== targetTrackName || !bgmSourceRef.current) {
                startBgm(targetTrackName);
            } else {
                const effectiveVolume = audioSettings.masterVolume * audioSettings.musicVolume;
                gainNode.gain.setTargetAtTime(effectiveVolume, ctx.currentTime, 0.1);
            }
        } else {
            stopBgm(0.5);
        }
    }, [isLoaded, targetTrackName, audioSettings.masterVolume, audioSettings.musicVolume, audioSettings.masterEnabled, audioSettings.musicEnabled, startBgm, stopBgm]);

    // SFX 볼륨 업데이트 (설정 변경 시 즉각 반영)
    useEffect(() => {
        if (!isLoaded) return;
        const gainNode = sfxGainRef.current;
        const ctx = contextRef.current;
        if (gainNode && ctx) {
            const isMuted = !audioSettings.masterEnabled || !audioSettings.sfxEnabled;
            const effectiveVolume = isMuted ? 0 : audioSettings.masterVolume * audioSettings.sfxVolume;
            gainNode.gain.setTargetAtTime(effectiveVolume, ctx.currentTime, 0.05);
        }
    }, [isLoaded, audioSettings.masterVolume, audioSettings.sfxVolume, audioSettings.masterEnabled, audioSettings.sfxEnabled]);

    // SFX 이벤트 리스너
    useEffect(() => {
        const handleSfxRequest = (e: any) => {
            if (e.detail?.file) {
                playSfx(e.detail.file);
            }
        };
        window.addEventListener('play-sfx', handleSfxRequest);
        return () => window.removeEventListener('play-sfx', handleSfxRequest);
    }, [playSfx]);

    // 브라우저 Autoplay 정책 대응
    useEffect(() => {
        const handleInteraction = () => {
            if (contextRef.current && contextRef.current.state === 'suspended') {
                contextRef.current.resume();
            }
        };
        window.addEventListener('mousedown', handleInteraction, { once: true });
        window.addEventListener('touchstart', handleInteraction, { once: true });
        return () => {
            window.removeEventListener('mousedown', handleInteraction);
            window.removeEventListener('touchstart', handleInteraction);
        };
    }, []);

    return null;
};

export default AudioManager;

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { useGame } from '../context/GameContext';
import { getMusicUrl, getAudioUrl } from '../utils';

/**
 * AudioManager
 * Web Audio API(AudioContext)를 사용하여 배경음(BGM)과 효과음(SFX)을 통합 관리합니다.
 */
const AudioManager: React.FC = () => {
    const { state } = useGame();
    const audioSettings = state.settings.audio;
    const activeDungeonId = state.activeManualDungeon?.dungeonId;

    const contextRef = useRef<AudioContext | null>(null);
    const bgmGainRef = useRef<GainNode | null>(null);
    const sfxGainRef = useRef<GainNode | null>(null);
    const bgmSourceRef = useRef<AudioBufferSourceNode | null>(null);

    const bgmCache = useRef<Map<string, AudioBuffer>>(new Map());
    const sfxCache = useRef<Map<string, AudioBuffer>>(new Map());
    const currentTrackName = useRef<string | null>(null);
    const [isLoaded, setIsLoaded] = useState(false);

    // 1. 현재 상황에 맞는 BGM 트랙 결정
    const targetTrackName = useMemo(() => {
        if (activeDungeonId === 'dungeon_t1_sewers') {
            return 'dungeon_track_01.mp3';
        }
        return 'track_01.mp3';
    }, [activeDungeonId]);

    // 2. 오디오 시스템 초기화
    useEffect(() => {
        const AudioCtx = window.AudioContext || (window as any).webkitAudioContext;
        const ctx = new AudioCtx();

        const bgmGain = ctx.createGain();
        const sfxGain = ctx.createGain();

        bgmGain.connect(ctx.destination);
        sfxGain.connect(ctx.destination);

        contextRef.current = ctx;
        bgmGainRef.current = bgmGain;
        sfxGainRef.current = sfxGain;

        if ('mediaSession' in navigator) {
            navigator.mediaSession.metadata = null;
            navigator.mediaSession.playbackState = 'none';
        }

        setIsLoaded(true);

        return () => {
            stopBgm(0);
            if (contextRef.current) {
                contextRef.current.close();
            }
        };
    }, []);

    /**
     * BGM 중지 로직
     */
    const stopBgm = useCallback((fadeTime: number = 0.3) => {
        const gainNode = bgmGainRef.current;
        const source = bgmSourceRef.current;
        const ctx = contextRef.current;

        if (source && gainNode && ctx) {
            const currentGain = gainNode.gain.value;
            gainNode.gain.cancelScheduledValues(ctx.currentTime);
            gainNode.gain.setValueAtTime(currentGain, ctx.currentTime);
            gainNode.gain.linearRampToValueAtTime(0, ctx.currentTime + fadeTime);

            setTimeout(() => {
                try { source.stop(); } catch (e) {}
                source.disconnect();
                if (bgmSourceRef.current === source) {
                    bgmSourceRef.current = null;
                    currentTrackName.current = null;
                }
            }, fadeTime * 1000 + 50);
        } else if (source) {
            try { source.stop(); } catch(e) {}
            source.disconnect();
            bgmSourceRef.current = null;
            currentTrackName.current = null;
        }
    }, []);

    /**
     * BGM 재생 시작
     */
    const startBgm = useCallback(async (trackName: string) => {
        const ctx = contextRef.current;
        const gainNode = bgmGainRef.current;
        if (!ctx || !gainNode) return;

        if (currentTrackName.current === trackName && bgmSourceRef.current) return;

        stopBgm(0.2); 

        try {
            let buffer = bgmCache.current.get(trackName);
            if (!buffer) {
                const url = getMusicUrl(trackName);
                const response = await fetch(url);

                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status} at ${url}`);
                }

                const contentType = response.headers.get('content-type');
                if (contentType && contentType.includes('text/html')) {
                    throw new Error(`Invalid content type: received HTML instead of audio at ${url}`);
                }

                const arrayBuffer = await response.arrayBuffer();
                buffer = await ctx.decodeAudioData(arrayBuffer);
                bgmCache.current.set(trackName, buffer);
            }

            if (targetTrackName !== trackName) return;

            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.loop = true;
            source.connect(gainNode);

            const effectiveVolume = audioSettings.masterVolume * audioSettings.musicVolume;
            gainNode.gain.cancelScheduledValues(ctx.currentTime);
            gainNode.gain.setValueAtTime(0, ctx.currentTime);
            gainNode.gain.linearRampToValueAtTime(effectiveVolume, ctx.currentTime + 0.5);

            if (ctx.state === 'suspended') await ctx.resume();

            source.start(0);
            bgmSourceRef.current = source;
            currentTrackName.current = trackName;
        } catch (e) {
            console.warn(`[Audio] BGM [${trackName}] play failed:`, e);
        }
    }, [targetTrackName, audioSettings.masterVolume, audioSettings.musicVolume, stopBgm]);

    /**
     * SFX 재생 로직
     */
    const playSfx = useCallback(async (filename: string) => {
        const ctx = contextRef.current;
        const gainNode = sfxGainRef.current;
        if (!ctx || !gainNode) return;

        // 설정 확인
        if (!audioSettings.masterEnabled || !audioSettings.sfxEnabled) {
            console.debug(`[Audio] SFX [${filename}] skip (Muted)`);
            return;
        }

        try {
            let buffer = sfxCache.current.get(filename);
            if (!buffer) {
                const url = getAudioUrl(filename);
                const response = await fetch(url);

                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status} for ${filename} at ${url}`);
                }

                const contentType = response.headers.get('content-type');
                if (contentType && contentType.includes('text/html')) {
                    throw new Error(`Invalid content type: received HTML instead of audio for ${filename} at ${url}`);
                }

                const arrayBuffer = await response.arrayBuffer();
                buffer = await ctx.decodeAudioData(arrayBuffer);
                sfxCache.current.set(filename, buffer);
            }

            if (ctx.state === 'suspended') {
                await ctx.resume();
            }

            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.connect(gainNode);
            source.start(0);
            console.debug(`[Audio] Playing SFX: ${filename}`);
        } catch (e) {
            console.error(`[Audio] SFX [${filename}] error:`, e);
        }
    }, [audioSettings.masterEnabled, audioSettings.sfxEnabled]);

    // BGM 설정 업데이트
    useEffect(() => {
        if (!isLoaded) return;
        const gainNode = bgmGainRef.current;
        const ctx = contextRef.current;
        if (!gainNode || !ctx) return;

        const shouldPlay = audioSettings.masterEnabled && audioSettings.musicEnabled;
        if (shouldPlay) {
            if (currentTrackName.current !== targetTrackName || !bgmSourceRef.current) {
                startBgm(targetTrackName);
            } else {
                const effectiveVolume = audioSettings.masterVolume * audioSettings.musicVolume;
                gainNode.gain.setTargetAtTime(effectiveVolume, ctx.currentTime, 0.1);
            }
        } else {
            stopBgm(0.5);
        }
    }, [isLoaded, targetTrackName, audioSettings.masterVolume, audioSettings.musicVolume, audioSettings.masterEnabled, audioSettings.musicEnabled, startBgm, stopBgm]);

    // SFX 볼륨 업데이트 (설정 변경 시 즉각 반영)
    useEffect(() => {
        if (!isLoaded) return;
        const gainNode = sfxGainRef.current;
        const ctx = contextRef.current;
        if (gainNode && ctx) {
            const isMuted = !audioSettings.masterEnabled || !audioSettings.sfxEnabled;
            const effectiveVolume = isMuted ? 0 : audioSettings.masterVolume * audioSettings.sfxVolume;
            gainNode.gain.setTargetAtTime(effectiveVolume, ctx.currentTime, 0.05);
        }
    }, [isLoaded, audioSettings.masterVolume, audioSettings.sfxVolume, audioSettings.masterEnabled, audioSettings.sfxEnabled]);

    // SFX 이벤트 리스너
    useEffect(() => {
        const handleSfxRequest = (e: any) => {
            if (e.detail?.file) {
                playSfx(e.detail.file);
            }
        };
        window.addEventListener('play-sfx', handleSfxRequest);
        return () => window.removeEventListener('play-sfx', handleSfxRequest);
    }, [playSfx]);

    // 브라우저 Autoplay 정책 대응
    useEffect(() => {
        const handleInteraction = () => {
            if (contextRef.current && contextRef.current.state === 'suspended') {
                contextRef.current.resume();
            }
        };
        window.addEventListener('mousedown', handleInteraction, { once: true });
        window.addEventListener('touchstart', handleInteraction, { once: true });
        return () => {
            window.removeEventListener('mousedown', handleInteraction);
            window.removeEventListener('touchstart', handleInteraction);
        };
    }, []);

    return null;
};

export default AudioManager;

const SESSION_VERSION = Date.now();

/**
 * 이미지 등 일반 에셋의 URL을 생성합니다.
 */
export const getAssetUrl = (filename: string, folder?: string): string => {
  const baseUrl = 'https://raw.githubusercontent.com/cryingdev/lockharts-forge/sub/assets/';

  let path = filename;
  if (folder) {
    const cleanFolder = folder.endsWith('/') ? folder.slice(0, -1) : folder;
    const cleanFile = filename.startsWith('/') ? filename.slice(1) : filename;
    path = `${cleanFolder}/${cleanFile}`;
  }

  return `${baseUrl}${path}?v=${SESSION_VERSION}`;
};

/**
 * sfx 폴더 내의 오디오 에셋 URL을 생성합니다.
 * 경로가 assets/audio/sfx/로 고정되어 있습니다.
 */
export const getAudioUrl = (filename: string): string => {
  const baseUrl = 'https://raw.githubusercontent.com/cryingdev/lockharts-forge/sub/assets/audio/sfx/';
  const cleanFile = filename.startsWith('/') ? filename.slice(1) : filename;
  return `${baseUrl}${cleanFile}?v=${SESSION_VERSION}`;
};

/**
 * audio/tracks 폴더 내의 음악 트랙 URL을 생성합니다.
 */
export const getMusicUrl = (filename: string): string => {
    const baseUrl = 'https://raw.githubusercontent.com/cryingdev/lockharts-forge/sub/assets/audio/tracks/';
    const cleanFile = filename.startsWith('/') ? filename.slice(1) : filename;
    return `${baseUrl}${cleanFile}?v=${SESSION_VERSION}`;
};

/**
 * Formats a duration in milliseconds to a MM:SS string.
 */
export const formatDuration = (ms: number): string => {
    if (ms <= 0) return '00:00';
    const totalSeconds = Math.floor(ms / 1000);
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;
    return `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
};

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';
import { ManualDungeonSession, RoomType } from '../types/game-state';

export type CameraMode = 'LOCKED' | 'ADAPTIVE' | 'FREE';

export interface DungeonSceneData {
    session: ManualDungeonSession;
    moveEnergy: number;
    bossEnergy: number;
    onMove: (dx: number, dy: number) => void;
    cameraMode: CameraMode;
    initialZoom?: number;
}

export default class DungeonScene extends Phaser.Scene {
    declare public add: Phaser.GameObjects.GameObjectFactory;
    declare public tweens: Phaser.Tweens.TweenManager;
    declare public scale: Phaser.Scale.ScaleManager;
    declare public cameras: Phaser.Cameras.Scene2D.CameraManager;
    declare public input: Phaser.Input.InputPlugin;
    declare public time: Phaser.Time.Clock;
    declare public events: Phaser.Events.EventEmitter;
    declare public load: Phaser.Loader.LoaderPlugin;
    declare public textures: Phaser.Textures.TextureManager;
    declare public anims: Phaser.Animations.AnimationManager;

    private session!: ManualDungeonSession;
    private onMoveCallback!: (dx: number, dy: number) => void;
    private cameraMode: CameraMode = 'LOCKED';
    private zoom: number = 1.0;

    private root!: Phaser.GameObjects.Container;
    private mapLayer!: Phaser.GameObjects.Container;
    private contentLayer!: Phaser.GameObjects.Container;
    private playerLayer!: Phaser.GameObjects.Container;
    private fxLayer!: Phaser.GameObjects.Container;

    private playerMarker!: Phaser.GameObjects.Container;
    private revealedTiles: Set<string> = new Set();
    private contentByCoord: Map<string, Phaser.GameObjects.Text> = new Map();

    private sprayEmitter!: Phaser.GameObjects.Particles.ParticleEmitter;
    private vignette!: Phaser.GameObjects.Graphics;
    private redFocusOverlay!: Phaser.GameObjects.Graphics;

    private uiCamera!: Phaser.Cameras.Scene2D.Camera;

    private tileWidth = 84;
    private tileGap = 8;
    private isMoving = false;

    private isDragging = false;
    private dragStartX = 0;
    private dragStartY = 0;

    private cameraTrackTween: Phaser.Tweens.Tween | null = null;
    private pixelateFX: any = null;

    constructor() {
        super('DungeonScene');
    }

    init(data: DungeonSceneData) {
        this.session = data.session;
        this.onMoveCallback = data.onMove;
        this.cameraMode = data.cameraMode ?? 'LOCKED';
        this.zoom = data.initialZoom ?? 1.0;
    }

    preload() {
        this.load.image('sparkle', getAssetUrl('particle_spark1.png'));
        this.load.image('red_mist', getAssetUrl('particle_spark2.png'));
    }

    create() {
        const { width, height } = this.scale;

        this.cameras.main.setBackgroundColor(0x000000);
        this.cameras.main.setZoom(this.zoom);

        this.uiCamera = this.cameras.add(0, 0, width, height).setName('HUD');
        this.uiCamera.setScroll(0, 0);
        this.uiCamera.setZoom(1);

        this.root = this.add.container(0, 0);
        this.mapLayer = this.add.container(0, 0);
        this.contentLayer = this.add.container(0, 0);
        this.playerLayer = this.add.container(0, 0);
        this.fxLayer = this.add.container(0, 0).setDepth(100);

        this.root.add([this.mapLayer, this.contentLayer, this.playerLayer]);

        this.vignette = this.add.graphics().setDepth(200).setScrollFactor(0);
        this.redFocusOverlay = this.add.graphics().setDepth(210).setScrollFactor(0);

        this.cameras.main.ignore([this.vignette, this.redFocusOverlay]);
        this.uiCamera.ignore(this.root);

        this.sprayEmitter = this.add.particles(0, 0, 'sparkle', {
            speed: { min: 60, max: 140 },
            scale: { start: 0.6, end: 0 },
            alpha: { start: 1, end: 0 },
            lifespan: 800,
            gravityY: 80,
            blendMode: 'ADD',
            emitting: false
        });
        this.root.add(this.sprayEmitter);

        this.initialRender();
        this.createPlayer();
        this.alignViewToPlayer(); 

        this.scale.on('resize', (gameSize: Phaser.Structs.Size) => {
            this.uiCamera.setSize(gameSize.width, gameSize.height);
            this.alignViewToPlayer();
            this.drawRedFocus();
        }, this);
        this.setupDragControls();

        this.drawRedFocus();
    }

    public updateZoom(newZoom: number) {
        this.zoom = newZoom;
        this.cameras.main.setZoom(newZoom);
        this.alignViewToPlayer();
    }

    public setCameraMode(mode: CameraMode) {
        this.cameraMode = mode;
        if (mode === 'LOCKED' && !this.isMoving) {
            this.alignViewToPlayer(); 
        }
    }

    private drawRedFocus() {
        const { width, height } = this.scale;
        this.redFocusOverlay.clear();

        const isFocusNeeded = this.session.encounterStatus === 'ENCOUNTERED' || this.session.encounterStatus === 'BATTLE';
        if (!isFocusNeeded) return;

        this.redFocusOverlay.setScale(1);

        const thickness = 140; 
        const color = 0x7f1d1d;
        const outerAlpha = 0.75;
        const innerAlpha = 0;

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, outerAlpha, outerAlpha, innerAlpha, innerAlpha);
        this.redFocusOverlay.fillRect(0, 0, width, thickness);

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, innerAlpha, innerAlpha, outerAlpha, outerAlpha);
        this.redFocusOverlay.fillRect(0, height - thickness, width, thickness);

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, outerAlpha, innerAlpha, outerAlpha, innerAlpha);
        this.redFocusOverlay.fillRect(0, 0, thickness, height);

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, innerAlpha, outerAlpha, innerAlpha, outerAlpha);
        this.redFocusOverlay.fillRect(width - thickness, 0, thickness, height);
    }

    public playEncounterEffect() {
        this.cameras.main.zoomTo(2.5, 2000, 'Cubic.easeInOut');

        if (this.cameras.main.postFX) {
            this.pixelateFX = this.cameras.main.postFX.addPixelate(2);
            this.tweens.add({
                targets: this.pixelateFX,
                amount: 32,
                duration: 2000,
                ease: 'Quad.easeIn'
            });
        }

        this.cameras.main.shake(2000, 0.005);
    }

    public resetEncounterEffect(targetZoom: number) {
        this.cameras.main.zoomTo(targetZoom, 1000, 'Cubic.easeOut');

        if (this.pixelateFX) {
            this.tweens.add({
                targets: this.pixelateFX,
                amount: 2,
                duration: 800,
                ease: 'Quad.easeOut',
                onComplete: () => {
                    if (this.cameras.main.postFX) {
                        this.cameras.main.postFX.remove(this.pixelateFX);
                    }
                    this.pixelateFX = null;
                }
            });
        }
    }

    public showFloatingGold(amount: number) {
        const x = this.playerMarker.x;
        const y = this.playerMarker.y;

        const floatText = this.add.text(x, y - 40, `💰 +${amount}G`, {
            fontFamily: 'Grenze Gotisch',
            fontSize: '32px',
            color: '#fbbf24',
            fontStyle: 'bold',
            stroke: '#000000',
            strokeThickness: 5,
            shadow: { color: '#000', fill: true, blur: 10 }
        }).setOrigin(0.5).setDepth(300);

        this.tweens.add({
            targets: floatText,
            y: y - 140,
            alpha: 0,
            scale: 1.2,
            duration: 1200,
            ease: 'Cubic.easeOut',
            onComplete: () => floatText.destroy()
        });
    }

    private setupDragControls() {
        this.input.on('pointerdown', (pointer: Phaser.Input.Pointer) => {
            if (this.session.encounterStatus === 'BATTLE' || this.session.encounterStatus === 'ENCOUNTERED') return;
            this.isDragging = true;
            this.dragStartX = pointer.x - this.root.x;
            this.dragStartY = pointer.y - this.root.y;

            if (this.cameraTrackTween) {
                this.cameraTrackTween.stop();
                this.cameraTrackTween = null;
            }
        });

        this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
            if (!this.isDragging) return;
            this.root.setPosition(pointer.x - this.dragStartX, pointer.y - this.dragStartY);
        });

        this.input.on('pointerup', () => { this.isDragging = false; });
    }

    private initialRender() {
        const { grid, visited } = this.session;
        const rows = grid.length;
        const cols = grid[0].length;

        this.mapLayer.removeAll(true);
        this.contentLayer.removeAll(true);
        this.revealedTiles.clear();
        this.contentByCoord.clear();

        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                if (visited[y][x]) {
                    this.drawRevealedTile(x, y, grid[y][x], false);
                }
            }
        }
    }

    private drawRevealedTile(x: number, y: number, type: RoomType, animate: boolean) {
        const key = `${x},${y}`;
        const tx = x * (this.tileWidth + this.tileGap);
        const ty = y * (this.tileWidth + this.tileGap);

        if (!this.revealedTiles.has(key)) {
            const tile = this.add.rectangle(tx, ty, this.tileWidth, this.tileWidth, 0x1c1917)
                .setStrokeStyle(2, 0x44403c)
                .setOrigin(0.5);
            this.mapLayer.add(tile);
            if (animate) {
                this.sprayEmitter.emitParticleAt(tx, ty, 15);
                tile.setAlpha(0).setScale(0.7);
                this.tweens.add({ targets: tile, alpha: 1, scale: 1, duration: 600, ease: 'Back.easeOut' });
            }
            this.revealedTiles.add(key);
        }

        const content = this.createRoomContents(type, tx, ty);
        if (content) {
            this.contentByCoord.set(key, content);
            if (animate) {
                content.setAlpha(0).setScale(0.5);
                this.tweens.add({ targets: content, alpha: 1, scale: 1, duration: 500, delay: 200, ease: 'Cubic.easeOut' });
            }
        }
    }

    private createRoomContents(type: RoomType, x: number, y: number) {
        let content: Phaser.GameObjects.Text | null = null;
        switch (type) {
            case 'BOSS':
                content = this.add.text(x, y, '💀', { fontSize: '32px' }).setOrigin(0.5);
                if (this.session.isBossLocked && !this.session.hasKey) content.setAlpha(0.3);
                break;
            case 'ENEMY':
                content = this.add.text(x, y, '⚔️', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'RESOURCE':
                content = this.add.text(x, y, Math.random() > 0.5 ? '💎' : '📦', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'STAIRS':
                content = this.add.text(x, y, '🪜', { fontSize: '32px' }).setOrigin(0.5);
                break;
            case 'KEY': content = this.add.text(x, y, '🔑', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'ENTRANCE': content = this.add.text(x, y, '🚪', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'GOLD': content = this.add.text(x, y, '💰', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'TRAP': content = this.add.text(x, y, '🕸️', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'NPC':
                if (this.session.npcFound) return null;
                content = this.add.text(x, y, '👤', { fontSize: '30px' }).setOrigin(0.5);
                break;
        }
        if (content) this.contentLayer.add(content);
        return content;
    }

    private createPlayer() {
        const { x, y } = this.session.playerPos;
        const px = x * (this.tileWidth + this.tileGap);
        const py = y * (this.tileWidth + this.tileGap);
        const visual = this.add.container(0, 0);
        const circle = this.add.circle(0, 0, 26, 0x6366f1, 0.9).setStrokeStyle(3, 0xffffff);
        const icon = this.add.text(0, 0, '👤', { fontSize: '24px' }).setOrigin(0.5);
        visual.add([circle, icon]);
        this.playerMarker = this.add.container(px, py, [visual]);
        this.playerLayer.add(this.playerMarker);
        this.tweens.add({ targets: visual, y: -8, duration: 800, yoyo: true, repeat: -1, ease: 'Sine.easeInOut' });
    }

    private alignViewToPlayer() {
        const { width, height } = this.scale;
        const { x, y } = this.session.playerPos;
        const targetX = x * (this.tileWidth + this.tileGap);
        const targetY = y * (this.tileWidth + this.tileGap);
        this.root.setPosition((width / 2) - (targetX), (height / 2) - (targetY));
    }

    public updateSession(newSession: ManualDungeonSession) {
        const oldStatus = this.session.encounterStatus;
        const oldFloor = this.session.currentFloor;
        this.session = newSession;

        if (oldFloor !== newSession.currentFloor) {
            this.initialRender();
        }

        if (oldStatus !== newSession.encounterStatus) this.drawRedFocus();
        const { width, height } = this.scale;
        const { x, y } = newSession.playerPos;
        const targetLocalX = x * (this.tileWidth + this.tileGap);
        const targetLocalY = y * (this.tileWidth + this.tileGap);
        this.isMoving = true;
        this.tweens.add({
            targets: this.playerMarker, x: targetLocalX, y: targetLocalY, duration: 300, ease: 'Cubic.out',
            onComplete: () => { this.isMoving = false; this.initialRender(); }
        });
        if (this.cameraMode !== 'FREE') {
            const targetRootX = (width / 2) - targetLocalX;
            const targetRootY = (height / 2) - targetLocalY;
            if (this.cameraTrackTween) this.cameraTrackTween.stop();
            this.cameraTrackTween = this.tweens.add({ targets: this.root, x: targetRootX, y: targetRootY, duration: 600, ease: 'Cubic.out' });
        }
    }

    public move(dx: number, dy: number) {
        if (this.isMoving) return;
        this.onMoveCallback(dx, dy);
    }
}

