import React from 'react';
import { AlertTriangle } from 'lucide-react';
import { UI_MODAL_LAYOUT } from '../../config/ui-config';

interface ConfirmationModalProps {
    isOpen: boolean;
    title: string;
    message: string;
    confirmLabel?: string;
    cancelLabel?: string;
    onConfirm: () => void;
    onCancel: () => void;
    isDanger?: boolean;
}

