import React, { useState, useEffect } from 'react';
import { Save, Upload, X, Trash2, Clock, Coins, Calendar, ChevronRight } from 'lucide-react';
import { getSaveMetadataList, SaveMetadata, deleteSlot } from '../../utils/saveSystem';
import ConfirmationModal from './ConfirmationModal';

interface SaveLoadModalProps {
    isOpen: boolean;
    mode: 'SAVE' | 'LOAD';
    onClose: () => void;
    onAction: (slotIndex: number) => void;
}

const SaveLoadModal: React.FC<SaveLoadModalProps> = ({ isOpen, mode, onClose, onAction }) => {
    const [metaList, setMetaList] = useState<SaveMetadata[]>([]);
    const [deleteConfirm, setDeleteConfirm] = useState<{ isOpen: boolean, index: number | null }>({
        isOpen: false,
        index: null
    });

    useEffect(() => {
        if (isOpen) {
            setMetaList(getSaveMetadataList());
        }
    }, [isOpen]);

    if (!isOpen) return null;

    const slots = [0, 1, 2]; // 3개의 슬롯 지원

    const playClick = () => {
        window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'item_click.mp3' } }));
    };

    const formatDate = (ts: number) => {
        return new Intl.DateTimeFormat('ko-KR', {
            month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
        }).format(new Date(ts));
    };

    const requestDelete = (e: React.MouseEvent, index: number) => {
        e.stopPropagation();
        playClick();
        setDeleteConfirm({ isOpen: true, index });
    };

    const handleConfirmDelete = () => {
        if (deleteConfirm.index !== null) {
            deleteSlot(deleteConfirm.index);
            setMetaList(getSaveMetadataList());
            setDeleteConfirm({ isOpen: false, index: null });
        }
    };

    const handleSlotClick = (index: number) => {
        playClick();
        onAction(index);
        if (mode === 'SAVE') {
            setTimeout(() => setMetaList(getSaveMetadataList()), 100);
        }
    };

    return (
        <>
            <div className="fixed inset-0 z-[1500] flex items-center justify-center bg-black/80 backdrop-blur-md px-[10%] py-[15%] overflow-hidden animate-in fade-in duration-200">
                <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-[92vw] max-w-[450px] h-fit max-h-full min-h-[300px] min-w-[280px] shadow-[0_40px_80px_-20px_rgba(0,0,0,0.9)] overflow-hidden flex flex-col animate-in zoom-in-95 duration-200 mx-auto">

                    {/* Header */}
                    <div className="p-4 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="bg-stone-800 p-2 rounded-xl border border-stone-700 text-amber-500">
                                {mode === 'SAVE' ? <Save className="w-5 h-5" /> : <Upload className="w-5 h-5" />}
                            </div>
                            <h3 className="font-bold font-serif text-lg text-stone-200 tracking-wide uppercase">
                                {mode === 'SAVE' ? 'Save Game' : 'Load Game'}
                            </h3>
                        </div>
                        <button onClick={() => { playClick(); onClose(); }} className="p-2 hover:bg-stone-800 rounded-full text-stone-500 hover:text-stone-300 transition-colors ml-4">
                            <X className="w-5 h-5" />
                        </button>
                    </div>

                    {/* Slot List */}
                    <div className="p-4 space-y-3 overflow-y-auto flex-1 custom-scrollbar min-h-0">
                        {slots.map(index => {
                            const meta = metaList.find(m => m.index === index);
                            return (
                                <div 
                                    key={index}
                                    onClick={() => (meta || mode === 'SAVE') && handleSlotClick(index)}
                                    className={`group relative h-20 p-3 rounded-2xl border-2 transition-all flex flex-col justify-center gap-2 ${
                                        meta 
                                        ? 'bg-stone-800 border-stone-700 hover:border-amber-500 hover:bg-stone-750 cursor-pointer' 
                                        : mode === 'SAVE' 
                                            ? 'bg-stone-900 border-stone-800 border-dashed hover:border-stone-600 text-stone-600 cursor-pointer'
                                            : 'bg-stone-950 border-stone-900 text-stone-600 cursor-not-allowed opacity-60'
                                    }`}
                                >
                                    <div className="flex justify-between items-center w-full gap-4">
                                        <div className="flex items-center gap-2 min-w-0">
                                            <span className="font-black text-[10px] uppercase tracking-widest text-stone-500 group-hover:text-amber-500">Slot {index + 1}</span>
                                            {meta?.version && (
                                                <span className="px-1.5 py-0.5 bg-stone-950 rounded text-[7px] font-mono font-bold text-stone-600 border border-stone-800 group-hover:border-amber-900/50 group-hover:text-amber-700 transition-colors">
                                                    v{meta.version}
                                                </span>
                                            )}
                                        </div>
                                        {meta && (
                                            <div className="flex items-center gap-2 shrink-0">
                                                <div className="flex items-center gap-1 text-[9px] text-stone-500 font-mono">
                                                    <Clock className="w-2.5 h-2.5" /> {formatDate(meta.timestamp)}
                                                </div>
                                                <button onClick={(e) => requestDelete(e, index)} className="p-1 hover:text-red-500 transition-colors">
                                                    <Trash2 className="w-3.5 h-3.5" />
                                                </button>
                                            </div>
                                        )}
                                    </div>

                                    {meta ? (
                                        <div className="flex items-center justify-between w-full gap-4">
                                            <div className="flex items-center gap-4">
                                                <div className="flex items-center gap-1.5">
                                                    <Calendar className="w-3.5 h-3.5 text-stone-500" />
                                                    <span className="text-xs md:text-sm font-bold text-stone-200">Day {meta.day}</span>
                                                </div>
                                                <div className="flex items-center gap-1.5">
                                                    <Coins className="w-3.5 h-3.5 text-amber-500" />
                                                    <span className="text-xs md:text-sm font-bold text-amber-400 font-mono">{meta.gold}G</span>
                                                </div>
                                            </div>
                                            <ChevronRight className="w-5 h-5 text-stone-600 group-hover:text-amber-500 group-hover:translate-x-1 transition-all" />
                                        </div>
                                    ) : (
                                        <div className="w-full py-0.5">
                                            <div className="text-center text-[10px] font-black uppercase tracking-[0.2em] italic opacity-70">
                                                {mode === 'SAVE' ? 'Click to Record Progress' : 'Empty Data Slot'}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>

                    <div className="p-3 bg-stone-950 text-center border-t border-stone-800 shrink-0">
                        <p className="text-[9px] md:text-[10px] text-stone-600 font-mono uppercase tracking-tighter">Your progress is kept in browser local storage.</p>
                    </div>
                </div>
            </div>

            <ConfirmationModal 
                isOpen={deleteConfirm.isOpen}
                title="Delete Save Data"
                message={`Are you sure you want to delete the data in Slot ${deleteConfirm.index !== null ? deleteConfirm.index + 1 : ''}? This action cannot be undone.`}
                confirmLabel="Delete Forever"
                onConfirm={handleConfirmDelete}
                onCancel={() => setDeleteConfirm({ isOpen: false, index: null })}
                isDanger={true}
            />
        </>
    );
};

export default SaveLoadModal;

import React, { useState } from 'react';
import { Save, Upload, Volume2, VolumeX, LogOut, X, Settings, Layout, Check, Music, Zap } from 'lucide-react';
import { useGame } from '../../context/GameContext';
import SaveLoadModal from './SaveLoadModal';
import { loadFromSlot } from '../../utils/saveSystem';
import ConfirmationModal from './ConfirmationModal';

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    onQuit: () => void;
    onLoadRequest: (data: any, depth: number) => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, onQuit, onLoadRequest }) => {
    const { state, actions } = useGame();
    const [slModal, setSlModal] = useState<{ isOpen: boolean, mode: 'SAVE' | 'LOAD' }>({ isOpen: false, mode: 'SAVE' });
    const [loadConfirm, setLoadConfirm] = useState<{ isOpen: boolean, data: any, index: number | null }>({
        isOpen: false,
        data: null,
        index: null
    });

    const APP_VERSION = "0.1.42a";

    if (!isOpen) return null;

    const audio = state.settings.audio;

    const playClick = () => {
        window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'item_click.mp3' } }));
    };

    const handleSlotAction = (slotIndex: number) => {
        if (slModal.mode === 'SAVE') {
            actions.saveGame(slotIndex);
        } else {
            const data = loadFromSlot(slotIndex);
            if (data) {
                if (data.version !== APP_VERSION) {
                    actions.showToast(`Load Failed: Version mismatch. (Save: v${data.version || '0.1.36'}, App: v${APP_VERSION})`);
                    return;
                }
                setLoadConfirm({ isOpen: true, data, index: slotIndex });
            }
        }
    };

    const handleConfirmLoad = () => {
        if (loadConfirm.data && loadConfirm.index !== null) {
            setLoadConfirm({ ...loadConfirm, isOpen: false });
            setSlModal({ ...slModal, isOpen: false });
            onClose();
            onLoadRequest(loadConfirm.data, loadConfirm.index);
        }
    };

    const toggleLogTicker = () => {
        playClick();
        actions.updateSettings({ showLogTicker: !state.settings.showLogTicker });
    };

    const toggleMasterAudio = () => {
        playClick();
        actions.updateSettings({
            audio: {
                ...audio,
                masterEnabled: !audio.masterEnabled
            }
        });
    };

    const updateVolume = (key: 'masterVolume' | 'musicVolume' | 'sfxVolume', value: number) => {
        if (!audio.masterEnabled) return;
        const enabledKey = key.replace('Volume', 'Enabled') as 'masterEnabled' | 'musicEnabled' | 'sfxEnabled';
        actions.updateSettings({
            audio: {
                ...audio,
                [key]: value,
                [enabledKey]: value > 0
            }
        });
    };

    const VolumeSlider = ({ label, value, icon: Icon, onChange, disabled }: { label: string, value: number, icon: any, onChange: (v: number) => void, disabled?: boolean }) => (
        <div className={`flex flex-col gap-1.5 p-3 rounded-xl border transition-all w-full ${disabled ? 'bg-stone-900/40 border-stone-800/50 opacity-40 grayscale' : 'bg-stone-800/40 border-stone-700/50'}`}>
            <div className="flex justify-between items-center">
                <div className="flex items-center gap-2">
                    <Icon className={`w-3.5 h-3.5 ${!disabled && value > 0 ? 'text-amber-500' : 'text-stone-600'}`} />
                    <span className="text-[9px] font-black text-stone-400 uppercase tracking-widest">{label}</span>
                </div>
                <span className="text-[9px] font-mono font-bold text-stone-500">{Math.round(value * 100)}%</span>
            </div>
            <input 
                type="range" min="0" max="1" step="0.01" 
                value={value} 
                disabled={disabled}
                onPointerDown={(e) => !disabled && e.stopPropagation()}
                onPointerMove={(e) => !disabled && e.stopPropagation()}
                onChange={(e) => !disabled && onChange(parseFloat(e.target.value))}
                onInput={(e) => !disabled && onChange(parseFloat((e.target as HTMLInputElement).value))}
                className={`w-full h-2.5 bg-stone-900 rounded-lg appearance-none cursor-pointer accent-amber-600 ${disabled ? 'cursor-not-allowed' : ''}`}
            />
        </div>
    );

    return (
        <>
