const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showRetreatConfirm, setShowRetreatConfirm] = useState(false);
    const [showLootOverlay, setShowLootOverlay] = useState(false);
    const [lastMsg, setLastMsg] = useState("");
    const [inspectedMercId, setInspectedMercId] = useState<string | null>(null);
    const [hasInteractedWithNpc, setHasInteractedWithNpc] = useState(false);

    // 함정 밟았는지 확인하기 위한 이전 위치 추적
    const lastPosRef = useRef(session?.playerPos ? { ...session.playerPos } : { x: -1, y: -1 });

    useEffect(() => {
        if (!session) return;

        const { x, y } = session.playerPos;
        const oldPos = lastPosRef.current;

        // 위치가 변경되었을 때만 트랩 체크
        if (x !== oldPos.x || y !== oldPos.y) {
            const currentTile = session.grid[y][x];
            // 함정 방이며 해당 메시지가 함정 발동을 알릴 때 효과 재생
            if (currentTile === 'TRAP' && session.lastActionMessage?.includes('springs')) {
                const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
                if (scene) scene.playTrapEffect();
                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'trap_triggered.mp3' } }));
            }
            lastPosRef.current = { x, y };
        }
    }, [session?.playerPos, session?.lastActionMessage]);

    // 골드 및 아이템 획득 상태 추적
    const prevGoldRef = useRef(session?.goldCollected || 0);
    const prevLootRef = useRef<any[]>(session?.collectedLoot || []);

    useEffect(() => {
        if (!session) return;

        // 1. 골드 획득 처리
        if (session.goldCollected > prevGoldRef.current) {
            const diff = session.goldCollected - prevGoldRef.current;
            window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'get_coin.mp3' } }));

            // 시각 효과 호출
            const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) scene.showFloatingGold(diff);
        }
        prevGoldRef.current = session.goldCollected;

        // 2. 아이템 획득 처리 (정밀 대조)
        const currentLoot = session.collectedLoot || [];
        const prevLoot = prevLootRef.current;
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;

        currentLoot.forEach(item => {
            const prevItem = prevLoot.find(p => p.id === item.id);
            const diff = item.count - (prevItem?.count || 0);

            if (diff > 0) {
                // 새로운 아이템이나 수량 증가 발견
                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'found_item.mp3' } }));
                if (scene) scene.showFloatingItem(item.id, diff);
            }
        });

        prevLootRef.current = [...currentLoot.map(i => ({ ...i }))];

    }, [session?.goldCollected, session?.collectedLoot]);

    // --- D-pad & Camera Zoom State ---
    const [dpadTransform, setDpadTransform] = useState(() => {
        const saved = localStorage.getItem('dpad_transform_v2'); 
        let parsed = saved ? JSON.parse(saved) : { x: 0, y: 0, scale: 0.8, opacity: 1.0 };
        if (parsed.scale > 1.2) parsed.scale = 1.2;
        if (parsed.scale < 0.4) parsed.scale = 0.4;
        if (parsed.opacity === undefined) parsed.opacity = 1.0;
        return parsed;
    });
    const [isDraggingDpad, setIsDraggingDpad] = useState(false);
    const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
    const [mapZoom, setMapZoom] = useState(1.0);
    const [showDpadMenu, setShowDpadMenu] = useState(false);

    const rafRef = useRef<number | null>(null);

    const dungeon = useMemo(() => 
        session ? DUNGEONS.find(d => d.id === session.dungeonId) : null,
        [session?.dungeonId]
    );

    const rescueTarget = useMemo(() => {
        if (!dungeon?.rescueMercenaryId) return null;
        return SPECIAL_RECRUITS_REGISTRY[dungeon.rescueMercenaryId] || null;
    }, [dungeon?.rescueMercenaryId]);

    const party = useMemo(() => {
        if (!session) return [];
        return state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    }, [session?.partyIds, state.knownMercenaries]);

    const isEncountered = session?.encounterStatus === 'ENCOUNTERED';
    const isBattle = session?.encounterStatus === 'BATTLE';
    const isStairs = session?.encounterStatus === 'STAIRS';
    const isVictory = session?.encounterStatus === 'VICTORY';
    const currentRoom = session ? session.grid[session.playerPos.y][session.playerPos.x] : null;

    useEffect(() => {
        setHasInteractedWithNpc(false);
    }, [session?.playerPos.x, session?.playerPos.y]);

    useEffect(() => {
        if (isEncountered && currentRoom && (currentRoom === 'ENEMY' || (currentRoom === 'BOSS' && !session.isBossDefeated))) {
            const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) {
                scene.playEncounterEffect();
            }

            const timer = setTimeout(() => {
                actions.startCombatManual();
            }, 2000); 

            return () => clearTimeout(timer);
        }
    }, [isEncountered, currentRoom, session?.isBossDefeated, actions]);

    const prevIsBattleRef = useRef(false);
    useEffect(() => {
        if (prevIsBattleRef.current && !isBattle) {
            const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) {
                scene.resetEncounterEffect(mapZoom);
            }
        }
        prevIsBattleRef.current = isBattle;
    }, [isBattle, mapZoom]);

    useEffect(() => {
        if (session?.lastActionMessage) {
            setLastMsg(session.lastActionMessage);
        }
    }, [session?.lastActionMessage]);

    useEffect(() => {
        if (!session || !rescueTarget) return;
        if (currentRoom === 'NPC' && !session.npcFound) {
            setLastMsg(`"Help! Please... is someone there? I don't think I can hold out much longer..."`);
        }
    }, [currentRoom, session?.npcFound, rescueTarget]);

    const handleDpadMove = (dx: number, dy: number) => {
        if (isEncountered || isBattle || isStairs) return;
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    const handleDragStart = (e: React.MouseEvent | React.TouchEvent) => {
        setIsDraggingDpad(true);
        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
        setDragStart({ x: clientX - dpadTransform.x, y: clientY - dpadTransform.y });
    };

    const handleDragMove = useCallback((e: MouseEvent | TouchEvent) => {
        if (!isDraggingDpad) return;
        if (rafRef.current) cancelAnimationFrame(rafRef.current);
        rafRef.current = requestAnimationFrame(() => {
            const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
            const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
            setDpadTransform((prev: any) => {
                const nextX = clientX - dragStart.x;
                const nextY = clientY - dragStart.y;
                return { ...prev, x: nextX, y: nextY };
            });
            rafRef.current = null;
        });
    }, [isDraggingDpad, dragStart.x, dragStart.y]);

    const handleDragEnd = useCallback(() => {
        if (isDraggingDpad) {
            setIsDraggingDpad(false);
            if (rafRef.current) {
                cancelAnimationFrame(rafRef.current);
                rafRef.current = null;
            }
            localStorage.setItem('dpad_transform_v2', JSON.stringify(dpadTransform));
        }
    }, [isDraggingDpad, dpadTransform]);

    useEffect(() => {
        if (isDraggingDpad) {
            window.addEventListener('mousemove', handleDragMove, { passive: true });
            window.addEventListener('mouseup', handleDragEnd);
            window.addEventListener('touchmove', handleDragMove, { passive: true });
            window.addEventListener('touchend', handleDragEnd);
        }
        return () => {
            window.removeEventListener('mousemove', handleDragMove);
            window.removeEventListener('mouseup', handleDragEnd);
            window.removeEventListener('touchmove', handleDragMove);
            window.removeEventListener('touchend', handleDragEnd);
        };
    }, [isDraggingDpad, handleDragMove, handleDragEnd]);

    const cycleDpadScale = () => {
        setDpadTransform((prev: any) => {
            let nextScale = prev.scale + 0.2;
            if (nextScale > 1.25) nextScale = 0.4;
            const next = { ...prev, scale: parseFloat(nextScale.toFixed(1)) };
            localStorage.setItem('dpad_transform_v2', JSON.stringify(next));
            return next;
        });
    };

    const handleOpacityChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = parseFloat(e.target.value);
        setDpadTransform((prev: any) => {
            const next = { ...prev, opacity: val };
            localStorage.setItem('dpad_transform_v2', JSON.stringify(next));
            return next;
        });
    };

    const handleZoom = (delta: number) => {
        const nextZoom = Math.min(1.5, Math.max(0.5, mapZoom + delta));
        setMapZoom(nextZoom);
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.updateZoom(nextZoom);
    };

    useEffect(() => {
        if (!isReady || !containerRef.current || !session || !dungeon) return;
        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO, parent: containerRef.current, width: containerRef.current.clientWidth, height: containerRef.current.clientHeight, backgroundColor: 'transparent', transparent: true, scene: [DungeonScene],
                scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
            };
            const game = new Phaser.Game(config);
            gameRef.current = game;
            game.scene.start('DungeonScene', { 
                session, 
                onMove: (dx: number, dy: number) => actions.moveInManualDungeon(dx, dy),
                initialZoom: mapZoom 
            });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) scene.updateSession(session);
        }
    }, [isReady, session, actions, dungeon]);

    useEffect(() => {
        const check = () => { if (containerRef.current?.clientWidth) setIsReady(true); else requestAnimationFrame(check); };
        check();
    }, []);

    if (!session || !dungeon) return null;

    const isOnNPCTile = currentRoom === 'NPC' && !session.npcFound;
    const inspectedMercenary = state.knownMercenaries.find(m => m.id === inspectedMercId) || null;

    const getDialogue = () => {
        if (isOnNPCTile) return { speaker: (rescueTarget?.name || "Survivor"), text: lastMsg };
        if (isEncountered) {
            if (currentRoom === 'BOSS' && session.isBossDefeated) return { speaker: "Inner Voice", text: "The terror is gone, but the air still trembles. We've taken what we came for. Time to leave?" };
            return { speaker: "Inner Voice", text: session.lastActionMessage || lastMsg };
        }
        if (isVictory) return { speaker: "Frontline Shout", text: "They're all down! Sector secured, Lockhart!" };
        if (isStairs) return { speaker: "The Path Ahead", text: lastMsg };
        return { speaker: "Exploration Log", text: lastMsg };
    };

    const { speaker, text: dialogueText } = getDialogue();

    const isEncounterAnimationActive = isEncountered && currentRoom && (currentRoom === 'ENEMY' || (currentRoom === 'BOSS' && !session.isBossDefeated));

    return (
        <div className="fixed inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">
            <div ref={containerRef} className={`absolute inset-0 z-0 transition-opacity ${isBattle ? 'opacity-20 blur-md' : 'opacity-100'}`} />

            {!isBattle && <SquadPanel party={party} onSelectMercenary={(id) => setInspectedMercId(id)} />}

            {/* Top Center: Floor Display */}
            {!isBattle && (
                <div className="absolute top-4 left-1/2 -translate-x-1/2 z-[110] flex items-center gap-3 px-4 py-2 bg-stone-900/90 backdrop-blur-md border border-amber-500/30 rounded-2xl shadow-2xl">
                    <Layers className="w-4 h-4 text-amber-50" />
                    <span className="text-xs md:text-sm font-black text-amber-50 uppercase tracking-widest font-mono">
                        Floor {session.currentFloor} / {session.maxFloors}
                    </span>
                </div>
            )}

            {/* Top Right: Vertical Control Stack */}
            <div className={`absolute top-4 right-4 z-[110] flex flex-col items-end gap-2 pointer-events-auto transition-opacity duration-500 ${isEncounterAnimationActive ? 'opacity-0' : 'opacity-100'}`}>
                <div className={`flex items-center gap-2 px-3 py-1.5 bg-stone-900/80 backdrop-blur-md border rounded-xl shadow-xl transition-all ${session.hasKey ? 'border-amber-500 text-amber-400' : 'border-white/5 text-stone-600 opacity-40'}`}>
                    <Key className={`w-4 h-4 ${session.hasKey ? 'animate-pulse' : ''}`} />
                    <span className="text-[10px] font-black uppercase tracking-widest">{session.hasKey ? 'Key Found' : 'No Key'}</span>
                </div>

                <div className="flex bg-stone-900/80 backdrop-blur-md border border-white/10 rounded-xl overflow-hidden shadow-2xl">
                    <button onClick={() => handleZoom(0.1)} className="p-2.5 hover:bg-stone-800 text-stone-300 transition-colors border-r border-white/5"><Plus className="w-4 h-4" /></button>
                    <div className="flex flex-col items-center justify-center px-2 min-w-[45px] select-none">
                        <span className="text-[8px] font-black text-stone-500 font-bold leading-none">ZOOM</span>
                        <span className="text-[10px] font-mono font-bold text-amber-500">{mapZoom.toFixed(1)}x</span>
                    </div>
                    <button onClick={() => handleZoom(-0.1)} className="p-2.5 hover:bg-stone-800 text-stone-300 transition-colors border-l border-white/5"><Minus className="w-4 h-4" /></button>
                </div>

                <button 
                    onClick={() => setShowRetreatConfirm(true)}
                    className="flex items-center gap-2 px-3 py-2 bg-red-950/40 hover:bg-red-900/60 border border-red-900/30 rounded-xl text-red-500 font-bold text-[10px] uppercase tracking-widest transition-all shadow-xl"
                >
                    <LogOut className="w-4 h-4" /> Retreat
                </button>

                <button 
                    onClick={() => setShowLootOverlay(true)}
                    className="flex items-center gap-2 px-3 py-2 bg-stone-900/80 backdrop-blur-md border border-amber-500/30 rounded-xl shadow-xl text-amber-400 hover:bg-stone-800 transition-all"
                >
                    <Package className="w-4 h-4" />
                    <span className="text-[10px] font-black uppercase tracking-widest">Loot Bag</span>
                </button>
            </div>

            {/* NPC Discovery Scene */}
            {isOnNPCTile && rescueTarget && (
                <div className="absolute inset-0 z-40 flex flex-col items-center justify-end pointer-events-none pb-20">
                    <div className="relative flex justify-center items-end w-full h-[80dvh] animate-in fade-in zoom-in slide-in-from-bottom-12 duration-1000 ease-out">
                        <div className="absolute bottom-[20%] left-1/2 -translate-x-1/2 w-64 h-64 bg-amber-500/20 blur-[80px] rounded-full -z-10 animate-pulse"></div>
                        <div className="absolute bottom-[10%] left-1/2 -translate-x-1/2 w-48 h-10 bg-black/60 blur-2xl rounded-full -z-10"></div>
                        <div className="absolute bottom-[30%] left-1/2 -translate-x-1/2 z-0">
                            <Sparkles className="w-12 h-12 text-amber-300 opacity-40 animate-bounce" />
                        </div>
                        <AnimatedMercenary
                            mercenary={rescueTarget}
                            className="h-full w-auto filter drop-shadow-[0_0_50px_rgba(245,158,11,0.5)] transition-all duration-500 relative z-10"
                        />
                    </div>
                </div>
            )}

            {isBattle && (
                <DungeonCombatView 
                    session={session} party={party} enemies={session.enemies || []} fleeChance={50}
                    onFinish={(win, final) => actions.resolveCombatManual(win, false, final)}
                    onFlee={(final) => actions.resolveCombatManual(false, true, final)}
                />
            )}

            {!isBattle && (
                <>
                    {/* Draggable D-pad Container */}
                    {(!isOnNPCTile || hasInteractedWithNpc) && (
                        <div 
                            className={`pointer-events-auto transition-all z-[200] select-none ${isDraggingDpad ? 'shadow-glow-amber cursor-grabbing' : 'cursor-default'} ${isEncounterAnimationActive ? 'opacity-0 scale-95' : 'opacity-100'}`}
                            style={{
                                position: 'absolute',
                                bottom: 'calc(22dvh + 32px)',
                                right: 16,
                                transform: `translate3d(${dpadTransform.x}px, ${dpadTransform.y}px, 0) scale(${dpadTransform.scale})`,
                                opacity: dpadTransform.opacity,
                                transformOrigin: 'bottom right',
                                willChange: 'transform'
                            }}
                        >
                            <div className="grid grid-cols-3 gap-2 bg-stone-900/90 backdrop-blur-xl p-3 rounded-3xl border border-white/10 shadow-2xl relative">

                                {showDpadMenu && (
                                    <div className="absolute -top-12 right-0 flex items-center gap-3 pointer-events-auto animate-in fade-in slide-in-from-bottom-2 duration-300">
                                        <div className="flex items-center gap-2 bg-stone-900/80 border border-white/10 px-3 py-1.5 rounded-full shadow-lg backdrop-blur-md">
                                            <Ghost className="w-3.5 h-3.5 text-stone-50" />
                                            <input 
                                                type="range" min="0.1" max="1.0" step="0.1"
                                                value={dpadTransform.opacity}
                                                onChange={handleOpacityChange}
                                                className="w-16 h-1 bg-stone-700 rounded-lg appearance-none cursor-pointer accent-amber-500"
                                            />
                                            <span className="text-[8px] font-mono font-bold text-stone-400 w-6">{Math.round(dpadTransform.opacity * 100)}%</span>
                                        </div>

                                        <div className="flex items-center gap-2">
                                            <div 
                                                onMouseDown={handleDragStart} onTouchStart={handleDragStart}
                                                className="w-9 h-9 bg-stone-800 border border-white/20 rounded-full flex items-center justify-center text-blue-400 cursor-grab active:cursor-grabbing hover:bg-stone-700 transition-all shadow-lg active:scale-95"
                                            >
                                                <Move className="w-4 h-4" />
                                            </div>
                                            <button 
                                                onClick={cycleDpadScale}
                                                className="w-9 h-9 bg-stone-800 border border-white/20 rounded-full flex items-center justify-center text-stone-300 hover:text-white transition-all shadow-lg active:scale-90"
                                            >
                                                {dpadTransform.scale >= 1.2 ? <Minimize className="w-4 h-4" /> : <Maximize className="w-4 h-4" />}
                                            </button>
                                        </div>
                                    </div>
                                )}

                                <div />
                                <button onClick={() => handleDpadMove(0,-1)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronUp /></button>

                                <button 
                                    onClick={() => setShowDpadMenu(!showDpadMenu)}
                                    className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${showDpadMenu ? 'bg-amber-600 text-white shadow-glow-amber' : 'bg-stone-800 text-stone-500 hover:text-stone-300'}`}
                                >
                                    <Settings className={`w-6 h-6 ${showDpadMenu ? 'animate-spin-slow' : ''}`} />
                                </button>

                                <button onClick={() => handleDpadMove(-1,0)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronLeft /></button>

                                <div className="w-12 h-12 bg-white/5 rounded-xl flex items-center justify-center text-stone-100/40">
                                    <Zap className="w-6 h-6" />
                                </div>

                                <button onClick={() => handleDpadMove(1,0)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronRight /></button>

                                <div />
                                <button onClick={() => handleDpadMove(0,1)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronDown /></button>
                                <div />
                            </div>
                        </div>
                    )}

                    {/* Bottom dialogue box container */}
                    <div className="absolute bottom-4 left-1/2 -translate-x-1/2 w-[95vw] max-w-5xl z-50 pointer-events-none">
                        <div className={`flex flex-col items-end gap-4 relative transition-all duration-500 ${isEncounterAnimationActive ? 'opacity-0 translate-y-8' : 'opacity-100 translate-y-0'}`}>
                            <DialogueBox 
                                speaker={speaker}
                                speakerAvatar={isOnNPCTile ? getAssetUrl(rescueTarget?.profileImage || 'default.png', 'mercenaries') : undefined}
                                text={dialogueText}
                                options={isOnNPCTile ? [
                                    { label: "GET THEM TO SAFETY", action: () => { 
                                        if (dungeon?.rescueMercenaryId) {
                                            actions.rescueMercenary(dungeon.rescueMercenaryId); 
                                            actions.showToast(`${rescueTarget?.name} has been secured!`); 
                                        }
                                    }, variant: 'primary' as const },
                                    { label: "WE'LL BE BACK FOR YOU", action: () => {
                                        setLastMsg("We've marked the spot. Resuming exploration for now.");
                                        setHasInteractedWithNpc(true);
                                    }, variant: 'neutral' as const }
                                ] : isEncountered ? [
                                    ...(currentRoom === 'BOSS' && session.isBossDefeated ? [
                                        { label: "CLAIM THE LOOT AND LEAVE", action: () => actions.finishManualAssault(), variant: 'primary' as const },
                                        { label: "CONTINUE EXPLORING", action: () => actions.resolveCombatManual(false, true, party), variant: 'neutral' as const }
                                    ] : [])
                                ] : isStairs ? [
                                    { label: `INTO THE ABYSS (Sector ${session.currentFloor + 1})`, action: () => actions.proceedToNextFloorManual(), variant: 'primary' as const },
                                    { label: "REACH THE SURFACE", action: () => actions.finishManualAssault(), variant: 'primary' as const },
                                    { label: "STAY IN THIS SECTOR", action: () => actions.resolveCombatManual(false, true, party), variant: 'neutral' as const }
                                ] : isVictory ? [
                                    { label: "RESUME SEARCH", action: () => actions.resolveCombatManual(false, true, party), variant: 'primary' as const }
                                ] : currentRoom === 'ENTRANCE' && session.isBossDefeated ? [
                                    { label: "END MISSION", action: () => actions.finishManualAssault(), variant: 'primary' as const }
                                ] : []}
                                className="w-full pointer-events-auto"
                            />
                        </div>
                    </div>
                </>
            )}

            {inspectedMercenary && (
                <MercenaryDetailModal 
                    mercenary={inspectedMercenary}
                    onClose={() => setInspectedMercId(null)}
                    onUnequip={(mercId, slot) => actions.unequipItem(mercId, slot)}
                    isReadOnly={false} 
                />
            )}

            {showLootOverlay && (
                <LootOverlay 
                    loot={session.collectedLoot} 
                    gold={session.goldCollected} 
                    onClose={() => setShowLootOverlay(false)} 
                />
            )}

            <ConfirmationModal isOpen={showRetreatConfirm} title="Abort Mission?" message="Extraction will return the squad to safety. No rewards will be collected." onConfirm={() => actions.retreatFromManualDungeon()} onCancel={() => setShowRetreatConfirm(false)} isDanger={true} />
        </div>
    );
};

export default AssaultNavigator;

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';
import { ManualDungeonSession, RoomType } from '../types/game-state';

export type CameraMode = 'LOCKED' | 'ADAPTIVE' | 'FREE';

export interface DungeonSceneData {
    session: ManualDungeonSession;
    moveEnergy: number;
    bossEnergy: number;
    onMove: (dx: number, dy: number) => void;
    cameraMode: CameraMode;
    initialZoom?: number;
}

export default class DungeonScene extends Phaser.Scene {
    declare public add: Phaser.GameObjects.GameObjectFactory;
    declare public tweens: Phaser.Tweens.TweenManager;
    declare public scale: Phaser.Scale.ScaleManager;
    declare public cameras: Phaser.Cameras.Scene2D.CameraManager;
    declare public input: Phaser.Input.InputPlugin;
    declare public time: Phaser.Time.Clock;
    declare public events: Phaser.Events.EventEmitter;
    declare public load: Phaser.Loader.LoaderPlugin;
    declare public textures: Phaser.Textures.TextureManager;
    declare public anims: Phaser.Animations.AnimationManager;

    private session!: ManualDungeonSession;
    private onMoveCallback!: (dx: number, dy: number) => void;
    private cameraMode: CameraMode = 'LOCKED';
    private zoom: number = 1.0;

    private root!: Phaser.GameObjects.Container;
    private mapLayer!: Phaser.GameObjects.Container;
    private contentLayer!: Phaser.GameObjects.Container;
    private playerLayer!: Phaser.GameObjects.Container;
    private fxLayer!: Phaser.GameObjects.Container;

    private playerMarker!: Phaser.GameObjects.Container;
    private playerCircle!: Phaser.GameObjects.Arc;
    private playerVisual!: Phaser.GameObjects.Container;

    private revealedTiles: Set<string> = new Set();
    private contentByCoord: Map<string, Phaser.GameObjects.Text> = new Map();

    private sprayEmitter!: Phaser.GameObjects.Particles.ParticleEmitter;
    private vignette!: Phaser.GameObjects.Graphics;
    private redFocusOverlay!: Phaser.GameObjects.Graphics;

    private uiCamera!: Phaser.Cameras.Scene2D.Camera;

    private tileWidth = 84;
    private tileGap = 8;
    private isMoving = false;

    private isDragging = false;
    private dragStartX = 0;
    private dragStartY = 0;

    private cameraTrackTween: Phaser.Tweens.Tween | null = null;
    private pixelateFX: any = null;

    constructor() {
        super('DungeonScene');
    }

    init(data: DungeonSceneData) {
        this.session = data.session;
        this.onMoveCallback = data.onMove;
        this.cameraMode = data.cameraMode ?? 'LOCKED';
        this.zoom = data.initialZoom ?? 1.0;
    }

    preload() {
        this.load.image('sparkle', getAssetUrl('particle_spark1.png'));
        this.load.image('red_mist', getAssetUrl('particle_spark2.png'));
    }

    create() {
        const { width, height } = this.scale;

        this.cameras.main.setBackgroundColor(0x000000);
        this.cameras.main.setZoom(this.zoom);

        this.uiCamera = this.cameras.add(0, 0, width, height).setName('HUD');
        this.uiCamera.setScroll(0, 0);
        this.uiCamera.setZoom(1);

        this.root = this.add.container(0, 0);
        this.mapLayer = this.add.container(0, 0);
        this.contentLayer = this.add.container(0, 0);
        this.playerLayer = this.add.container(0, 0);
        this.fxLayer = this.add.container(0, 0).setDepth(100);

        // Add layers to root so they move together
        this.root.add([this.mapLayer, this.contentLayer, this.playerLayer, this.fxLayer]);

        this.vignette = this.add.graphics().setDepth(200).setScrollFactor(0);
        this.redFocusOverlay = this.add.graphics().setDepth(210).setScrollFactor(0);

        this.cameras.main.ignore([this.vignette, this.redFocusOverlay]);
        this.uiCamera.ignore(this.root);

        this.sprayEmitter = this.add.particles(0, 0, 'sparkle', {
            speed: { min: 60, max: 140 },
            scale: { start: 0.6, end: 0 },
            alpha: { start: 1, end: 0 },
            lifespan: 800,
            gravityY: 80,
            blendMode: 'ADD',
            emitting: false
        });
        this.root.add(this.sprayEmitter);

        this.initialRender();
        this.createPlayer();
        this.alignViewToPlayer(); 

        this.scale.on('resize', (gameSize: Phaser.Structs.Size) => {
            this.uiCamera.setSize(gameSize.width, gameSize.height);
            this.alignViewToPlayer();
            this.drawRedFocus();
        }, this);
        this.setupDragControls();

        this.drawRedFocus();
    }

    public updateZoom(newZoom: number) {
        this.zoom = newZoom;
        this.cameras.main.setZoom(newZoom);
        this.alignViewToPlayer();
    }

    public setCameraMode(mode: CameraMode) {
        this.cameraMode = mode;
        if (mode === 'LOCKED' && !this.isMoving) {
            this.alignViewToPlayer(); 
        }
    }

    private drawRedFocus() {
        const { width, height } = this.scale;
        this.redFocusOverlay.clear();

        const isFocusNeeded = this.session.encounterStatus === 'ENCOUNTERED' || this.session.encounterStatus === 'BATTLE';
        if (!isFocusNeeded) return;

        this.redFocusOverlay.setScale(1);

        const thickness = 140; 
        const color = 0x7f1d1d;
        const outerAlpha = 0.75;
        const innerAlpha = 0;

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, outerAlpha, outerAlpha, innerAlpha, innerAlpha);
        this.redFocusOverlay.fillRect(0, 0, width, thickness);

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, innerAlpha, innerAlpha, outerAlpha, outerAlpha);
        this.redFocusOverlay.fillRect(0, height - thickness, width, thickness);

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, outerAlpha, innerAlpha, outerAlpha, innerAlpha);
        this.redFocusOverlay.fillRect(0, 0, thickness, height);

        this.redFocusOverlay.fillGradientStyle(color, color, color, color, innerAlpha, outerAlpha, innerAlpha, outerAlpha);
        this.redFocusOverlay.fillRect(width - thickness, 0, thickness, height);
    }

    public playEncounterEffect() {
        this.cameras.main.zoomTo(2.5, 2000, 'Cubic.easeInOut');

        if (this.cameras.main.postFX) {
            this.pixelateFX = this.cameras.main.postFX.addPixelate(2);
            this.tweens.add({
                targets: this.pixelateFX,
                amount: 32,
                duration: 2000,
                ease: 'Quad.easeIn'
            });
        }

        this.cameras.main.shake(2000, 0.005);
    }

    public resetEncounterEffect(targetZoom: number) {
        this.cameras.main.zoomTo(targetZoom, 1000, 'Cubic.easeOut');

        if (this.pixelateFX) {
            this.tweens.add({
                targets: this.pixelateFX,
                amount: 2,
                duration: 800,
                ease: 'Quad.easeOut',
                onComplete: () => {
                    if (this.cameras.main.postFX) {
                        this.cameras.main.postFX.remove(this.pixelateFX);
                    }
                    this.pixelateFX = null;
                }
            });
        }
    }

    public showFloatingGold(amount: number) {
        const x = this.playerMarker.x;
        const y = this.playerMarker.y;

        const floatText = this.add.text(x, y - 40, `💰 +${amount}G`, {
            fontFamily: 'Grenze Gotisch',
            fontSize: '32px',
            color: '#fbbf24',
            fontStyle: 'bold',
            stroke: '#000000',
            strokeThickness: 5,
            shadow: { color: '#000', fill: true, blur: 10 }
        }).setOrigin(0.5).setDepth(300);

        // Add to root so it moves with the map
        this.root.add(floatText);

        this.tweens.add({
            targets: floatText,
            y: y - 140,
            alpha: 0,
            scale: 1.2,
            duration: 1200,
            ease: 'Cubic.easeOut',
            onComplete: () => floatText.destroy()
        });
    }

    /**
     * 아이템 획득 시 이미지와 수량이 머리 위로 떠오르는 효과
     */
    public showFloatingItem(itemId: string, amount: number) {
        const x = this.playerMarker.x + (Math.random() * 40 - 20); // 약간의 위치 편차
        const y = this.playerMarker.y;

        const key = `item_${itemId}`;
        const renderFloating = () => {
            const container = this.add.container(x, y - 50).setDepth(310);

            // Add to root so it moves with the map
            this.root.add(container);

            const icon = this.add.image(0, 0, key).setDisplaySize(42, 42);
            const text = this.add.text(25, 0, `x${amount}`, {
                fontFamily: 'Grenze Gotisch',
                fontSize: '24px',
                color: '#ffffff',
                stroke: '#000000',
                strokeThickness: 4,
                fontStyle: 'bold'
            }).setOrigin(0, 0.5);

            container.add([icon, text]);
            container.setAlpha(0).setScale(0.5);

            this.tweens.add({
                targets: container,
                y: y - 160,
                alpha: { from: 0, to: 1 },
                scale: 1.2,
                duration: 400,
                ease: 'Back.out'
            });

            this.tweens.add({
                targets: container,
                y: y - 220,
                alpha: 0,
                delay: 800,
                duration: 600,
                ease: 'Cubic.in',
                onComplete: () => container.destroy()
            });
        };

        if (this.textures.exists(key)) {
            renderFloating();
        } else {
            // 텍스처가 없는 경우 동적으로 로드 후 렌더링
            this.load.image(key, getAssetUrl(`${itemId}.png`, 'materials'));
            this.load.once('complete', renderFloating);
            this.load.start();
        }
    }

    /**
     * 함정 밟았을 때 빨간색 깜빡임 및 흔들림 효과
     */
    public playTrapEffect() {
        if (!this.playerCircle || !this.playerVisual) return;

        // 원 색상을 빨간색으로 변경
        this.playerCircle.setFillStyle(0xef4444, 1);

        // 흔들림 효과 (더 빠르게 조정하여 타격감 개선)
        this.tweens.add({
            targets: this.playerVisual,
            x: { from: -8, to: 8 },
            duration: 50,
            yoyo: true,
            repeat: 2,
            ease: 'Sine.easeInOut',
            onComplete: () => {
                // 위치 즉시 초기화
                this.playerVisual.setX(0);
            }
        });

        // 0.1초(100ms) 후 즉시 색상 복구 시작
        this.time.delayedCall(100, () => {
            this.tweens.add({
                targets: this.playerCircle,
                fillColor: 0x6366f1,
                duration: 100,
                ease: 'Linear'
            });
        });
    }

    private setupDragControls() {
        this.input.on('pointerdown', (pointer: Phaser.Input.Pointer) => {
            if (this.session.encounterStatus === 'BATTLE' || this.session.encounterStatus === 'ENCOUNTERED') return;
            this.isDragging = true;
            this.dragStartX = pointer.x - this.root.x;
            this.dragStartY = pointer.y - this.root.y;

            if (this.cameraTrackTween) {
                this.cameraTrackTween.stop();
                this.cameraTrackTween = null;
            }
        });

        this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
            if (!this.isDragging) return;
            this.root.setPosition(pointer.x - this.dragStartX, pointer.y - this.dragStartY);
        });

        this.input.on('pointerup', () => { this.isDragging = false; });
    }

    private initialRender() {
        const { grid, visited } = this.session;
        const rows = grid.length;
        const cols = grid[0].length;

        this.mapLayer.removeAll(true);
        this.contentLayer.removeAll(true);
        this.revealedTiles.clear();
        this.contentByCoord.clear();

        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                if (visited[y][x]) {
                    this.drawRevealedTile(x, y, grid[y][x], false);
                }
            }
        }
    }

    private drawRevealedTile(x: number, y: number, type: RoomType, animate: boolean) {
        const key = `${x},${y}`;
        const tx = x * (this.tileWidth + this.tileGap);
        const ty = y * (this.tileWidth + this.tileGap);

        if (!this.revealedTiles.has(key)) {
            const tile = this.add.rectangle(tx, ty, this.tileWidth, this.tileWidth, 0x1c1917)
                .setStrokeStyle(2, 0x44403c)
                .setOrigin(0.5);
            this.mapLayer.add(tile);
            if (animate) {
                this.sprayEmitter.emitParticleAt(tx, ty, 15);
                tile.setAlpha(0).setScale(0.7);
                this.tweens.add({ targets: tile, alpha: 1, scale: 1, duration: 600, ease: 'Back.easeOut' });
            }
            this.revealedTiles.add(key);
        }

        const content = this.createRoomContents(type, tx, ty);
        if (content) {
            this.contentByCoord.set(key, content);
            if (animate) {
                content.setAlpha(0).setScale(0.5);
                this.tweens.add({ targets: content, alpha: 1, scale: 1, duration: 500, delay: 200, ease: 'Cubic.easeOut' });
            }
        }
    }

    private createRoomContents(type: RoomType, x: number, y: number) {
        let content: Phaser.GameObjects.Text | null = null;
        switch (type) {
            case 'BOSS':
                content = this.add.text(x, y, '💀', { fontSize: '32px' }).setOrigin(0.5);
                if (this.session.isBossLocked && !this.session.hasKey) content.setAlpha(0.3);
                break;
            case 'ENEMY':
                content = this.add.text(x, y, '⚔️', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'RESOURCE':
                content = this.add.text(x, y, Math.random() > 0.5 ? '💎' : '📦', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'STAIRS':
                content = this.add.text(x, y, '🪜', { fontSize: '32px' }).setOrigin(0.5);
                break;
            case 'KEY': content = this.add.text(x, y, '🔑', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'ENTRANCE': content = this.add.text(x, y, '🚪', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'GOLD': content = this.add.text(x, y, '💰', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'TRAP': content = this.add.text(x, y, '🕸️', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'NPC':
                if (this.session.npcFound) return null;
                content = this.add.text(x, y, '👤', { fontSize: '30px' }).setOrigin(0.5);
                break;
        }
        if (content) this.contentLayer.add(content);
        return content;
    }

    private createPlayer() {
        const { x, y } = this.session.playerPos;
        const px = x * (this.tileWidth + this.tileGap);
        const py = y * (this.tileWidth + this.tileGap);

        this.playerVisual = this.add.container(0, 0);
        this.playerCircle = this.add.circle(0, 0, 26, 0x6366f1, 0.9).setStrokeStyle(3, 0xffffff);
        const icon = this.add.text(0, 0, '👤', { fontSize: '24px' }).setOrigin(0.5);

        this.playerVisual.add([this.playerCircle, icon]);
        this.playerMarker = this.add.container(px, py, [this.playerVisual]);
        this.playerLayer.add(this.playerMarker);

        this.tweens.add({ 
            targets: this.playerVisual, 
            y: -8, 
            duration: 800, 
            yoyo: true, 
            repeat: -1, 
            ease: 'Sine.easeInOut' 
        });
    }

    private alignViewToPlayer() {
        const { width, height } = this.scale;
        const { x, y } = this.session.playerPos;
        const targetX = x * (this.tileWidth + this.tileGap);
        const targetY = y * (this.tileWidth + this.tileGap);
        this.root.setPosition((width / 2) - (targetX), (height / 2) - (targetY));
    }

    public updateSession(newSession: ManualDungeonSession) {
        const oldStatus = this.session.encounterStatus;
        const oldFloor = this.session.currentFloor;
        this.session = newSession;

        if (oldFloor !== newSession.currentFloor) {
            this.initialRender();
        }

        if (oldStatus !== newSession.encounterStatus) this.drawRedFocus();
        const { width, height } = this.scale;
        const { x, y } = newSession.playerPos;
        const targetLocalX = x * (this.tileWidth + this.tileGap);
        const targetLocalY = y * (this.tileWidth + this.tileGap);
        this.isMoving = true;
        this.tweens.add({
            targets: this.playerMarker, x: targetLocalX, y: targetLocalY, duration: 300, ease: 'Cubic.out',
            onComplete: () => { this.isMoving = false; this.initialRender(); }
        });
        if (this.cameraMode !== 'FREE') {
            const targetRootX = (width / 2) - targetLocalX;
            const targetRootY = (height / 2) - targetLocalY;
            if (this.cameraTrackTween) this.cameraTrackTween.stop();
            this.cameraTrackTween = this.tweens.add({ targets: this.root, x: targetRootX, y: targetRootY, duration: 600, ease: 'Cubic.out' });
        }
    }

    public move(dx: number, dy: number) {
        if (this.isMoving) return;
        this.onMoveCallback(dx, dy);
    }
}

import { GameState, ManualDungeonSession, RoomType, DungeonResult, InventoryItem } from '../../types/index';
import { DUNGEONS } from '../../data/dungeons';
import { handleClaimExpedition } from './expedition';
import { MONSTERS } from '../../data/monsters';
import { materials } from '../../data/materials';
import { calculateMaxHp, calculateMaxMp, mergePrimaryStats } from '../../models/Stats';
import { Monster } from '../../models/Monster';
import { MONSTER_DROPS } from '../../data/monster-drops';

/**
 * 랜덤한 입구와 그에 따른 가장 먼 출구를 포함한 그리드를 생성합니다.
 */
const generateManualGrid = (width: number, height: number, dungeonId: string, floor: number, maxFloors: number, canSpawnNPC: boolean = false): { grid: RoomType[][], startPos: { x: number, y: number } } => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));

    // 1. 입구 위치 랜덤 결정 (외곽 벽면 중 하나)
    let startX, startY;
    if (Math.random() < 0.5) {
        startX = Math.random() < 0.5 ? 0 : width - 1;
        startY = Math.floor(Math.random() * height);
    } else {
        startX = Math.floor(Math.random() * width);
        startY = Math.random() < 0.5 ? 0 : height - 1;
    }

    grid[startY][startX] = 'ENTRANCE';

    // 2. 입구에서 가장 먼 반대편 코너를 출구로 설정
    const endX = startX < width / 2 ? width - 1 : 0;
    const endY = startY < height / 2 ? height - 1 : 0;

    if (floor === maxFloors) {
        grid[endY][endX] = 'BOSS';
    } else {
        grid[endY][endX] = 'STAIRS';
    }

    // 3. 열쇠 배치 (보스 층인 경우)
    if (floor === maxFloors) {
        let keyPlaced = false;
        let attempts = 0;
        while (!keyPlaced && attempts < 100) {
            let kx = Math.floor(Math.random() * width);
            let ky = Math.floor(Math.random() * height);
            if (grid[ky][kx] === 'EMPTY') {
                grid[ky][kx] = 'KEY';
                keyPlaced = true;
            }
            attempts++;
        }
    }

    // 4. 기타 요소들 배치 (적, 자원, 함정 등)
    let npcPlaced = false;
    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const r = Math.random();
                if (r < 0.18) grid[y][x] = 'ENEMY'; 
                else if (r < 0.33) grid[y][x] = 'RESOURCE'; 
                else if (r < 0.38) grid[y][x] = 'GOLD';
                else if (r < 0.45) grid[y][x] = 'TRAP';
                // GATED: Only spawn NPC if allowed and not already placed
                else if (canSpawnNPC && r < 0.47 && !npcPlaced) {
                    grid[y][x] = 'NPC';
                    npcPlaced = true;
                }
            }
        }
    }

    // NPC 강제 배치 (출현 확률 보정 - 1층에서만 발생)
    if (canSpawnNPC && !npcPlaced && floor === 1) {
        let attempts = 0;
        while (!npcPlaced && attempts < 50) {
            const rx = Math.floor(Math.random() * width);
            const ry = Math.floor(Math.random() * height);
            if (grid[ry][rx] === 'EMPTY') {
                grid[ry][rx] = 'NPC';
                npcPlaced = true;
            }
            attempts++;
        }
    }

    return { grid, startPos: { x: startX, y: startY } };
};

/**
 * 몬스터 조우 시 적 풀을 생성하는 헬퍼 함수
 */
const generateEnemiesForSession = (dungeonId: string, currentFloor: number, isBoss: boolean): Monster[] => {
    const dungeon = DUNGEONS.find(d => d.id === dungeonId);
    if (!dungeon) return [];

    let monsters: Monster[] = [];
    if (isBoss) {
        const monsterId = dungeon.bossVariantId || 'plague_rat_king';
        const monsterBase = MONSTERS[monsterId] || MONSTERS['giant_rat'];
        monsters = [{ ...monsterBase, currentHp: monsterBase.stats.maxHp }];
    } else {
        const pool = dungeon.monsterPools.find(p => currentFloor >= p.minFloor && currentFloor <= p.maxFloor);
        const mobIds = pool ? pool.monsterIds : ['giant_rat'];
        let monsterCount = Math.floor(Math.random() * dungeon.tier) + 1;
        if (currentFloor > 3) monsterCount += 1;
        monsterCount = Math.min(4, Math.max(1, monsterCount));

        for (let i = 0; i < monsterCount; i++) {
            const monsterId = mobIds[Math.floor(Math.random() * mobIds.length)];
            const monsterBase = MONSTERS[monsterId] || MONSTERS['giant_rat'];
            monsters.push({ ...monsterBase, currentHp: monsterBase.stats.maxHp });
        }
    }
    return monsters;
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string; partyIds: string[]; startFloor?: number }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const startFloor = payload.startFloor || 1;
    const party = state.knownMercenaries.filter(m => payload.partyIds.includes(m.id));

    if (party.some(m => (m.expeditionEnergy || 0) < dungeon.energyCost)) {
        return { ...state, logs: [`Your squad is too exhausted to enter ${dungeon.name}.`, ...state.logs] };
    }

    // --- RESCUE CHECK: Only spawn NPC if they are not already in the known pool ---
    const rescueId = dungeon.rescueMercenaryId;
    const isNpcAlreadySaved = rescueId ? state.knownMercenaries.some(m => m.id === rescueId) : true;
    const canSpawnNPC = !!rescueId && !isNpcAlreadySaved;

    const updatedMercs = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { 
                ...m, 
                expeditionEnergy: Math.max(0, (m.expeditionEnergy || 0) - dungeon.energyCost), 
                status: 'ON_EXPEDITION' as const 
            };
        }
        return m;
    });

    const { grid, startPos } = generateManualGrid(dungeon.gridWidth, dungeon.gridHeight, dungeon.id, startFloor, dungeon.maxFloors, canSpawnNPC);

    const visited = Array.from({ length: dungeon.gridHeight }, () => Array(dungeon.gridWidth).fill(false));
    visited[startPos.y][startPos.x] = true;

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos: startPos,
        pathHistory: [startPos],
        hasKey: false,
        isBossLocked: dungeon.isBossLocked ?? true,
        goldCollected: 0,
        collectedLoot: [],
        sessionXp: payload.partyIds.reduce((acc, id) => ({ ...acc, [id]: 0 }), {}),
        encounterStatus: 'NONE',
        lastActionMessage: `The air is thick with dampness. We've entered Sector ${startFloor}.`,
        currentFloor: startFloor,
        maxFloors: dungeon.maxFloors
    };

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`The squad has descended into ${dungeon.name}. Light is fading.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) {
        return { 
            ...state, 
            activeManualDungeon: { ...session, lastActionMessage: "The wall here is solid rock. No way through." }
        };
    }

    const targetRoom = session.grid[newY][newX];
    if (targetRoom === 'WALL') return state;

    const isAlreadyVisited = session.visited[newY][newX];

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 15);
            return { ...m, currentHp: nextHp };
        }
        return m;
    });

    const isWipedOut = updatedMercs.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);
    if (isWipedOut) return handleRetreatManualDungeon({ ...state, knownMercenaries: updatedMercs });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let nextCollectedLoot = [...session.collectedLoot];
    let logMsg = '';
    let actionMsg = session.lastActionMessage;
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';
    let newMaxFloorReached = { ...state.maxFloorReached };

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 30;
        newGrid[newY][newX] = 'EMPTY';
        actionMsg = `Hidden amongst the debris, we found an old pouch containing ${extraGold} Gold!`;
    } else if (targetRoom === 'RESOURCE' && !isAlreadyVisited) {
        const possibleResources = ['copper_ore', 'tin_ore', 'leather_strips', 'charcoal', 'hide_patch'];
        const resId = possibleResources[Math.floor(Math.random() * possibleResources.length)];
        const count = 1 + Math.floor(Math.random() * 2);
        const matDef = materials[resId];

        // 필드 자원도 세션 보관함(collectedLoot)에 추가하여 연출 및 결과 합산 처리
        const existingLoot = nextCollectedLoot.find(l => l.id === resId);
        if (existingLoot) {
            existingLoot.count += count;
        } else {
            nextCollectedLoot.push({ id: resId, count: count, name: matDef.name });
        }

        newGrid[newY][newX] = 'EMPTY';
        actionMsg = `Spotted something useful. Salvaged ${matDef.name} x${count} for the forge.`;
        logMsg = `Recovered valuable materials from the ruins.`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        actionMsg = `A click from beneath! A concealed trap springs, striking the squad!`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `The heavy iron key is now in our possession.`;
        actionMsg = `A heavy iron key... It likely unlocks the path to the sector's master.`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'ENEMY' && !isAlreadyVisited) {
        encounterStatus = 'ENCOUNTERED';
        actionMsg = `Shadows shift ahead... movement detected. steel yourselves!`;
    } else if (targetRoom === 'BOSS') {
        encounterStatus = 'ENCOUNTERED';
        actionMsg = session.isBossDefeated 
            ? `The champion of this lair lies defeated. We should secure the area.` 
            : `The air hums with a terrifying presence. We have reached the source of the corruption.`;
    } else if (targetRoom === 'STAIRS') {
        encounterStatus = 'STAIRS';
        actionMsg = `A narrow flight of stairs winds deeper into the darkness. Do we descend?`;
        const nextFloor = session.currentFloor + 1;
        newMaxFloorReached[session.dungeonId] = Math.max(newMaxFloorReached[session.dungeonId] || 1, nextFloor);
    }

    return {
        ...state,
        knownMercenaries: updatedMercs,
        maxFloorReached: newMaxFloorReached,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            pathHistory: [{ x: newX, y: newY }, ...session.pathHistory].slice(0, 50),
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold,
            collectedLoot: nextCollectedLoot, // 수동 탐사 자원 업데이트 반영
            lastActionMessage: actionMsg
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleProceedToNextFloorManual = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus !== 'STAIRS') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const nextFloor = session.currentFloor + 1;
    // Check if NPC should still spawn on deeper floors (rarely, but possible if missed)
    const rescueId = dungeon.rescueMercenaryId;
    const isNpcAlreadySaved = rescueId ? state.knownMercenaries.some(m => m.id === rescueId) : true;
    const canSpawnNPC = !!rescueId && !isNpcAlreadySaved && !session.npcFound;

    const { grid: nextGrid, startPos: nextStartPos } = generateManualGrid(dungeon.gridWidth, dungeon.gridHeight, dungeon.id, nextFloor, session.maxFloors, canSpawnNPC);

    const nextVisited = Array.from({ length: dungeon.gridHeight }, () => Array(dungeon.gridWidth).fill(false));
    nextVisited[nextStartPos.y][nextStartPos.x] = true;

    return {
        ...state,
        activeManualDungeon: {
            ...session,
            grid: nextGrid,
            visited: nextVisited,
            playerPos: nextStartPos,
            pathHistory: [nextStartPos],
            currentFloor: nextFloor,
            encounterStatus: 'NONE',
            lastActionMessage: `The stairs were long, but we've reached Sector ${nextFloor}. Stay alert.`
        },
        logs: [`The squad has descended deeper into the abyss. Floor ${nextFloor}.`, ...state.logs]
    };
};

export const handleStartCombatManual = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus !== 'ENCOUNTERED') return state;

    const currentRoom = session.grid[session.playerPos.y][session.playerPos.x];
    if (currentRoom === 'BOSS' && session.isBossDefeated) return state;

    const enemies = generateEnemiesForSession(session.dungeonId, session.currentFloor, currentRoom === 'BOSS');

    return {
        ...state,
        activeManualDungeon: {
            ...session,
            encounterStatus: 'BATTLE',
            enemies: enemies
        }
    };
};

export const handleResolveCombatManual = (state: GameState, payload: { win: boolean, flee: boolean, finalParty: any[] }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const currentRoom = session.grid[session.playerPos.y][session.playerPos.x];
    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);

    let logMsg = '';
    const livingMembers = payload.finalParty.filter(p => p.currentHp > 0);

    let totalXpGained = 0;
    const gainedLootInCombat: { id: string; count: number; name: string }[] = [];

    if (payload.win && session.enemies) {
        totalXpGained = session.enemies.reduce((sum, e) => sum + e.rewardXp, 0);

        session.enemies.forEach(enemy => {
            const drops = MONSTER_DROPS[enemy.id];
            if (drops) {
                drops.forEach(drop => {
                    if (Math.random() <= drop.chance) {
                        const qty = Math.floor(Math.random() * (drop.maxQuantity - drop.minQuantity + 1)) + drop.minQuantity;
                        if (qty > 0) {
                            const mat = materials[drop.itemId];
                            if (mat) {
                                gainedLootInCombat.push({ id: drop.itemId, count: qty, name: mat.name });
                            }
                        }
                    }
                });
            }
        });
    }

    const xpPerMemberBase = (payload.win && totalXpGained > 0 && livingMembers.length > 0) 
        ? Math.floor(totalXpGained / livingMembers.length) 
        : 0;

    const avgEnemyLevel = (session.enemies && session.enemies.length > 0)
        ? session.enemies.reduce((acc, e) => acc + e.level, 0) / session.enemies.length
        : 1;

    if (payload.win) {
        logMsg = `The last of them has fallen. The area is quiet again.`;
    }

    const nextSessionXp = { ...session.sessionXp };

    const newKnownMercenaries = state.knownMercenaries.map(m => {
        const combatant = payload.finalParty.find(p => p.id === m.id);
        if (combatant) {
            let nextXp = m.currentXp;
            let nextLevel = m.level;
            let nextMaxHp = m.maxHp;
            let nextMaxMp = m.maxMp;
            let nextCurrentHp = combatant.currentHp;
            let bonusStatPoints = m.bonusStatPoints || 0;

            if (payload.win && combatant.currentHp > 0) {
                const levelDiff = Math.max(0, m.level - Math.floor(avgEnemyLevel));
                const penaltyMult = Math.max(0.1, 1 - (levelDiff * 0.1));
                const xpToAdd = Math.floor(xpPerMemberBase * penaltyMult);

                nextXp += xpToAdd;
                nextSessionXp[m.id] = (nextSessionXp[m.id] || 0) + xpToAdd;

                while (nextXp >= m.xpToNextLevel) {
                    nextXp -= m.xpToNextLevel;
                    level++;
                    xpToNext = level * 100;
                    const merged = mergePrimaryStats(m.stats, m.allocatedStats);
                    nextMaxHp = calculateMaxHp(merged, nextLevel);
                    nextMaxMp = calculateMaxMp(merged, nextLevel);
                    nextCurrentHp = nextMaxHp;
                    bonusStatPoints += 3;
                }
            }

            return { 
                ...m, 
                currentHp: nextCurrentHp, 
                currentMp: combatant.currentMp,
                currentXp: nextXp,
                level: nextLevel,
                bonusStatPoints,
                maxHp: nextMaxHp,
                maxMp: nextMaxMp,
                xpToNextLevel: nextLevel * 100
            };
        }
        return m;
    });

    const isBossDefeatedNow = currentRoom === 'BOSS' && payload.win;
    const isBossDefeated = isBossDefeatedNow || session.isBossDefeated;

    const nextCollectedLoot = [...session.collectedLoot];
    gainedLootInCombat.forEach(item => {
        const existing = nextCollectedLoot.find(l => l.id === item.id);
        if (existing) existing.count += item.count;
        else nextCollectedLoot.push(item);
    });

    let nextGrid = [...session.grid.map(row => [...row])];
    if (payload.win && currentRoom === 'ENEMY') {
        nextGrid[session.playerPos.y][session.playerPos.x] = 'EMPTY';
    }

    const isDefeat = !payload.win && !payload.flee;

    if (isDefeat) {
        return handleRetreatManualDungeon({
            ...state,
            knownMercenaries: newKnownMercenaries,
            activeManualDungeon: {
                ...session,
                sessionXp: nextSessionXp,
                encounterStatus: 'DEFEAT'
            }
        });
    }

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        activeManualDungeon: {
            ...session,
            grid: nextGrid,
            collectedLoot: nextCollectedLoot,
            sessionXp: nextSessionXp,
            encounterStatus: payload.win ? 'VICTORY' : (payload.flee ? 'NONE' : 'DEFEAT'),
            isBossDefeated,
            lastActionMessage: payload.win 
                ? `Area neutralized. Squad, catch your breath.`
                : (payload.flee ? `We managed to pull back. Steel yourselves.` : `Everything's gone wrong... we need to get out.`)
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT' || 
                    state.knownMercenaries.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    const mercResults: DungeonResult['mercenaryResults'] = [];

    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            let statusChange: 'NONE' | 'INJURED' | 'DEAD' = 'NONE';

            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.1) { nextStatus = 'DEAD'; statusChange = 'DEAD'; }
                else { 
                    nextStatus = 'INJURED'; statusChange = 'INJURED'; 
                    m.recoveryUntilDay = state.stats.day + 2; 
                }
            } else if (m.currentHp <= 0) {
                nextStatus = 'INJURED'; statusChange = 'INJURED';
                m.recoveryUntilDay = state.stats.day + 1;
            }

            mercResults.push({
                id: m.id, name: m.name, job: m.job, levelBefore: m.level, levelAfter: m.level,
                xpGained: session.sessionXp[m.id] || 0,
                currentXp: m.currentXp, xpToNext: m.xpToNextLevel, statusChange
            });

            return { ...m, status: nextStatus, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        dungeonResult: isDefeat ? {
            dungeonName: dungeon?.name || 'Unknown',
            rewards: session.collectedLoot,
            goldGained: session.goldCollected,
            mercenaryResults: mercResults,
            isDefeat: true
        } : state.dungeonResult,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: The squad has been overwhelmed.' : 'Orderly withdrawal from the zone confirmed.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { 
            ...currentSession, 
            grid: newGrid, 
            npcFound: true, 
            rescuedNpcId: payload.npcId,
            lastActionMessage: `A survivor secured! Let's escort them back to the surface.`
        },
        logs: [`Escorting a survivor out of the depths.`, ...state.logs]
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const tempExpId = `temp_manual_${Date.now()}`;
    const tempExp = {
        id: tempExpId,
        dungeonId: session.dungeonId,
        partyIds: session.partyIds,
        startTime: 0,
        endTime: 0,
        status: 'COMPLETED' as const
    };

    const stateWithTempExp = {
        ...state,
        activeExpeditions: [...state.activeExpeditions, tempExp]
    };

    let newInventory = [...state.inventory];
    session.collectedLoot.forEach(loot => {
        const existing = newInventory.find(i => i.id === loot.id);
        if (existing) {
            newInventory = newInventory.map(i => i.id === loot.id ? { ...i, quantity: i.quantity + loot.count } : i);
        } else {
            const mat = materials[loot.id];
            if (mat) newInventory.push({ ...mat, quantity: loot.count } as InventoryItem);
        }
    });

    const claimedState = handleClaimExpedition({ ...stateWithTempExp, inventory: newInventory }, { 
        expeditionId: tempExpId, 
        rescuedNpcId: session.rescuedNpcId,
        isFullClear: !!session.isBossDefeated
    });

    if (claimedState.dungeonResult) {
        claimedState.dungeonResult.rewards = session.collectedLoot;
        if (session.goldCollected > 0) {
            claimedState.stats.gold += session.goldCollected;
            claimedState.dungeonResult.goldGained = (claimedState.dungeonResult.goldGained || 0) + session.goldCollected;
        }
        claimedState.dungeonResult.mercenaryResults = claimedState.dungeonResult.mercenaryResults.map(res => ({
            ...res,
            xpGained: session.sessionXp[res.id] || res.xpGained
        }));
    }

    return {
        ...claimedState,
        activeManualDungeon: null,
        showManualDungeonOverlay: false
    };
};

import { GameState, ManualDungeonSession, RoomType, DungeonResult, InventoryItem } from '../../types/index';
import { DUNGEONS } from '../../data/dungeons';
import { handleClaimExpedition } from './expedition';
import { MONSTERS } from '../../data/monsters';
import { materials } from '../../data/materials';
import { calculateMaxHp, calculateMaxMp, mergePrimaryStats } from '../../models/Stats';
import { Monster } from '../../models/Monster';
import { MONSTER_DROPS } from '../../data/monster-drops';

/**
 * 랜덤한 입구와 그에 따른 가장 먼 출구를 포함한 그리드를 생성합니다.
 */
const generateManualGrid = (width: number, height: number, dungeonId: string, floor: number, maxFloors: number, canSpawnNPC: boolean = false): { grid: RoomType[][], startPos: { x: number, y: number } } => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));

    // 1. 입구 위치 랜덤 결정 (외곽 벽면 중 하나)
    let startX, startY;
    if (Math.random() < 0.5) {
        startX = Math.random() < 0.5 ? 0 : width - 1;
        startY = Math.floor(Math.random() * height);
    } else {
        startX = Math.floor(Math.random() * width);
        startY = Math.random() < 0.5 ? 0 : height - 1;
    }

    grid[startY][startX] = 'ENTRANCE';

    // 2. 입구에서 가장 먼 반대편 코너를 출구로 설정
    const endX = startX < width / 2 ? width - 1 : 0;
    const endY = startY < height / 2 ? height - 1 : 0;

    if (floor === maxFloors) {
        grid[endY][endX] = 'BOSS';
    } else {
        grid[endY][endX] = 'STAIRS';
    }

    // 3. 열쇠 배치 (보스 층인 경우)
    if (floor === maxFloors) {
        let keyPlaced = false;
        let attempts = 0;
        while (!keyPlaced && attempts < 100) {
            let kx = Math.floor(Math.random() * width);
            let ky = Math.floor(Math.random() * height);
            if (grid[ky][kx] === 'EMPTY') {
                grid[ky][kx] = 'KEY';
                keyPlaced = true;
            }
            attempts++;
        }
    }

    // 4. 기타 요소들 배치 (적, 자원, 함정 등)
    let npcPlaced = false;
    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const r = Math.random();
                if (r < 0.18) grid[y][x] = 'ENEMY'; 
                else if (r < 0.33) grid[y][x] = 'RESOURCE'; 
                else if (r < 0.38) grid[y][x] = 'GOLD';
                else if (r < 0.45) grid[y][x] = 'TRAP';
                // GATED: Only spawn NPC if allowed and not already placed
                else if (canSpawnNPC && r < 0.47 && !npcPlaced) {
                    grid[y][x] = 'NPC';
                    npcPlaced = true;
                }
            }
        }
    }

    // NPC 강제 배치 (출현 확률 보정 - 1층에서만 발생)
    if (canSpawnNPC && !npcPlaced && floor === 1) {
        let attempts = 0;
        while (!npcPlaced && attempts < 50) {
            const rx = Math.floor(Math.random() * width);
            const ry = Math.floor(Math.random() * height);
            if (grid[ry][rx] === 'EMPTY') {
                grid[ry][rx] = 'NPC';
                npcPlaced = true;
            }
            attempts++;
        }
    }

    return { grid, startPos: { x: startX, y: startY } };
};

/**
 * 몬스터 조우 시 적 풀을 생성하는 헬퍼 함수
 */
const generateEnemiesForSession = (dungeonId: string, currentFloor: number, isBoss: boolean): Monster[] => {
    const dungeon = DUNGEONS.find(d => d.id === dungeonId);
    if (!dungeon) return [];

    let monsters: Monster[] = [];
    if (isBoss) {
        const monsterId = dungeon.bossVariantId || 'plague_rat_king';
        const monsterBase = MONSTERS[monsterId] || MONSTERS['giant_rat'];
        monsters = [{ ...monsterBase, currentHp: monsterBase.stats.maxHp }];
    } else {
        const pool = dungeon.monsterPools.find(p => currentFloor >= p.minFloor && currentFloor <= p.maxFloor);
        const mobIds = pool ? pool.monsterIds : ['giant_rat'];
        let monsterCount = Math.floor(Math.random() * dungeon.tier) + 1;
        if (currentFloor > 3) monsterCount += 1;
        monsterCount = Math.min(4, Math.max(1, monsterCount));

        for (let i = 0; i < monsterCount; i++) {
            const monsterId = mobIds[Math.floor(Math.random() * mobIds.length)];
            const monsterBase = MONSTERS[monsterId] || MONSTERS['giant_rat'];
            monsters.push({ ...monsterBase, currentHp: monsterBase.stats.maxHp });
        }
    }
    return monsters;
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string; partyIds: string[]; startFloor?: number }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const startFloor = payload.startFloor || 1;
    const party = state.knownMercenaries.filter(m => payload.partyIds.includes(m.id));

    if (party.some(m => (m.expeditionEnergy || 0) < dungeon.energyCost)) {
        return { ...state, logs: [`Your squad is too exhausted to enter ${dungeon.name}.`, ...state.logs] };
    }

    // --- RESCUE CHECK: Only spawn NPC if they are not already in the known pool ---
    const rescueId = dungeon.rescueMercenaryId;
    const isNpcAlreadySaved = rescueId ? state.knownMercenaries.some(m => m.id === rescueId) : true;
    const canSpawnNPC = !!rescueId && !isNpcAlreadySaved;

    const updatedMercs = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { 
                ...m, 
                expeditionEnergy: Math.max(0, (m.expeditionEnergy || 0) - dungeon.energyCost), 
                status: 'ON_EXPEDITION' as const 
            };
        }
        return m;
    });

    const { grid, startPos } = generateManualGrid(dungeon.gridWidth, dungeon.gridHeight, dungeon.id, startFloor, dungeon.maxFloors, canSpawnNPC);

    const visited = Array.from({ length: dungeon.gridHeight }, () => Array(dungeon.gridWidth).fill(false));
    visited[startPos.y][startPos.x] = true;

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos: startPos,
        pathHistory: [startPos],
        hasKey: false,
        isBossLocked: dungeon.isBossLocked ?? true,
        goldCollected: 0,
        collectedLoot: [],
        sessionXp: payload.partyIds.reduce((acc, id) => ({ ...acc, [id]: 0 }), {}),
        encounterStatus: 'NONE',
        lastActionMessage: `The air is thick with dampness. We've entered Sector ${startFloor}.`,
        currentFloor: startFloor,
        maxFloors: dungeon.maxFloors
    };

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`The squad has descended into ${dungeon.name}. Light is fading.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) {
        return { 
            ...state, 
            activeManualDungeon: { ...session, lastActionMessage: "The wall here is solid rock. No way through." }
        };
    }

    const targetRoom = session.grid[newY][newX];
    if (targetRoom === 'WALL') return state;

    const isAlreadyVisited = session.visited[newY][newX];

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 15);
            return { ...m, currentHp: nextHp };
        }
        return m;
    });

    const isWipedOut = updatedMercs.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);
    if (isWipedOut) return handleRetreatManualDungeon({ ...state, knownMercenaries: updatedMercs });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let nextCollectedLoot = [...session.collectedLoot];
    let logMsg = '';
    let actionMsg = session.lastActionMessage;
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';
    let newMaxFloorReached = { ...state.maxFloorReached };

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 30;
        newGrid[newY][newX] = 'EMPTY';
        actionMsg = `Hidden amongst the debris, we found an old pouch containing ${extraGold} Gold!`;
    } else if (targetRoom === 'RESOURCE' && !isAlreadyVisited) {
        const possibleResources = ['copper_ore', 'tin_ore', 'leather_strips', 'charcoal', 'hide_patch'];
        const resId = possibleResources[Math.floor(Math.random() * possibleResources.length)];
        const count = 1 + Math.floor(Math.random() * 2);
        const matDef = materials[resId];

        // 필드 자원도 세션 보관함(collectedLoot)에 추가하여 연출 및 결과 합산 처리
        const existingLoot = nextCollectedLoot.find(l => l.id === resId);
        if (existingLoot) {
            existingLoot.count += count;
        } else {
            nextCollectedLoot.push({ id: resId, count: count, name: matDef.name });
        }

        newGrid[newY][newX] = 'EMPTY';
        actionMsg = `Spotted something useful. Salvaged ${matDef.name} x${count} for the forge.`;
        logMsg = `Recovered valuable materials from the ruins.`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        actionMsg = `A click from beneath! A concealed trap springs, striking the squad!`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `The heavy iron key is now in our possession.`;
        actionMsg = `A heavy iron key... It likely unlocks the path to the sector's master.`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'ENEMY' && !isAlreadyVisited) {
        encounterStatus = 'ENCOUNTERED';
        actionMsg = `Shadows shift ahead... movement detected. steel yourselves!`;
    } else if (targetRoom === 'BOSS') {
        encounterStatus = 'ENCOUNTERED';
        actionMsg = session.isBossDefeated 
            ? `The champion of this lair lies defeated. We should secure the area.` 
            : `The air hums with a terrifying presence. We have reached the source of the corruption.`;
    } else if (targetRoom === 'STAIRS') {
        encounterStatus = 'STAIRS';
        actionMsg = `A narrow flight of stairs winds deeper into the darkness. Do we descend?`;
        const nextFloor = session.currentFloor + 1;
        newMaxFloorReached[session.dungeonId] = Math.max(newMaxFloorReached[session.dungeonId] || 1, nextFloor);
    }

    return {
        ...state,
        knownMercenaries: updatedMercs,
        maxFloorReached: newMaxFloorReached,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            pathHistory: [{ x: newX, y: newY }, ...session.pathHistory].slice(0, 50),
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold,
            collectedLoot: nextCollectedLoot, // 수동 탐사 자원 업데이트 반영
            lastActionMessage: actionMsg
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleProceedToNextFloorManual = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus !== 'STAIRS') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const nextFloor = session.currentFloor + 1;
    // Check if NPC should still spawn on deeper floors (rarely, but possible if missed)
    const rescueId = dungeon.rescueMercenaryId;
    const isNpcAlreadySaved = rescueId ? state.knownMercenaries.some(m => m.id === rescueId) : true;
    const canSpawnNPC = !!rescueId && !isNpcAlreadySaved && !session.npcFound;

    const { grid: nextGrid, startPos: nextStartPos } = generateManualGrid(dungeon.gridWidth, dungeon.gridHeight, dungeon.id, nextFloor, session.maxFloors, canSpawnNPC);

    const nextVisited = Array.from({ length: dungeon.gridHeight }, () => Array(dungeon.gridWidth).fill(false));
    nextVisited[nextStartPos.y][nextStartPos.x] = true;

    return {
        ...state,
        activeManualDungeon: {
            ...session,
            grid: nextGrid,
            visited: nextVisited,
            playerPos: nextStartPos,
            pathHistory: [nextStartPos],
            currentFloor: nextFloor,
            encounterStatus: 'NONE',
            lastActionMessage: `The stairs were long, but we've reached Sector ${nextFloor}. Stay alert.`
        },
        logs: [`The squad has descended deeper into the abyss. Floor ${nextFloor}.`, ...state.logs]
    };
};

export const handleStartCombatManual = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus !== 'ENCOUNTERED') return state;

    const currentRoom = session.grid[session.playerPos.y][session.playerPos.x];
    if (currentRoom === 'BOSS' && session.isBossDefeated) return state;

    const enemies = generateEnemiesForSession(session.dungeonId, session.currentFloor, currentRoom === 'BOSS');

    return {
        ...state,
        activeManualDungeon: {
            ...session,
            encounterStatus: 'BATTLE',
            enemies: enemies
        }
    };
};

export const handleResolveCombatManual = (state: GameState, payload: { win: boolean, flee: boolean, finalParty: any[] }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const currentRoom = session.grid[session.playerPos.y][session.playerPos.x];
    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);

    let logMsg = '';
    const livingMembers = payload.finalParty.filter(p => p.currentHp > 0);

    let totalXpGained = 0;
    const gainedLootInCombat: { id: string; count: number; name: string }[] = [];

    if (payload.win && session.enemies) {
        totalXpGained = session.enemies.reduce((sum, e) => sum + e.rewardXp, 0);

        session.enemies.forEach(enemy => {
            const drops = MONSTER_DROPS[enemy.id];
            if (drops) {
                drops.forEach(drop => {
                    if (Math.random() <= drop.chance) {
                        const qty = Math.floor(Math.random() * (drop.maxQuantity - drop.minQuantity + 1)) + drop.minQuantity;
                        if (qty > 0) {
                            const mat = materials[drop.itemId];
                            if (mat) {
                                gainedLootInCombat.push({ id: drop.itemId, count: qty, name: mat.name });
                            }
                        }
                    }
                });
            }
        });
    }

    const xpPerMemberBase = (payload.win && totalXpGained > 0 && livingMembers.length > 0) 
        ? Math.floor(totalXpGained / livingMembers.length) 
        : 0;

    const avgEnemyLevel = (session.enemies && session.enemies.length > 0)
        ? session.enemies.reduce((acc, e) => acc + e.level, 0) / session.enemies.length
        : 1;

    if (payload.win) {
        logMsg = `The last of them has fallen. The area is quiet again.`;
    }

    const nextSessionXp = { ...session.sessionXp };

    // Fix: Declared newKnownMercenaries with 'let'
    let newKnownMercenaries = state.knownMercenaries.map(m => {
        const combatant = payload.finalParty.find(p => p.id === m.id);
        if (combatant) {
            // Fix: Initialized currentXp and nextLevel based on current mercenary state.
            // Introduced xpToNext to handle threshold updates during potentially multiple level-ups.
            let currentXp = m.currentXp;
            let nextLevel = m.level;
            let xpToNext = m.xpToNextLevel || (nextLevel * 100);
            let nextMaxHp = m.maxHp;
            let nextMaxMp = m.maxMp;
            let nextCurrentHp = combatant.currentHp;
            let bonusStatPoints = m.bonusStatPoints || 0;

            if (payload.win && combatant.currentHp > 0) {
                const levelDiff = Math.max(0, m.level - Math.floor(avgEnemyLevel));
                const penaltyMult = Math.max(0.1, 1 - (levelDiff * 0.1));
                const xpToAdd = Math.floor(xpPerMemberBase * penaltyMult);

                currentXp += xpToAdd;
                nextSessionXp[m.id] = (nextSessionXp[m.id] || 0) + xpToAdd;

                // Fix: 'level' renamed to 'nextLevel', added local 'xpToNext' to fix 'Cannot find name' errors.
                while (currentXp >= xpToNext) {
                    currentXp -= xpToNext;
                    nextLevel++;
                    xpToNext = nextLevel * 100;
                    const merged = mergePrimaryStats(m.stats, m.allocatedStats);
                    nextMaxHp = calculateMaxHp(merged, nextLevel);
                    nextMaxMp = calculateMaxMp(merged, nextLevel);
                    nextCurrentHp = nextMaxHp;
                    bonusStatPoints += 3;
                }
            }

            return { 
                ...m, 
                currentHp: nextCurrentHp, 
                currentMp: combatant.currentMp,
                currentXp: currentXp,
                level: nextLevel,
                bonusStatPoints,
                maxHp: nextMaxHp,
                maxMp: nextMaxMp,
                xpToNextLevel: xpToNext
            };
        }
        return m;
    });

    const isBossDefeatedNow = currentRoom === 'BOSS' && payload.win;
    const isBossDefeated = isBossDefeatedNow || session.isBossDefeated;

    const nextCollectedLoot = [...session.collectedLoot];
    gainedLootInCombat.forEach(item => {
        const existing = nextCollectedLoot.find(l => l.id === item.id);
        if (existing) existing.count += item.count;
        else nextCollectedLoot.push(item);
    });

    let nextGrid = [...session.grid.map(row => [...row])];
    if (payload.win && currentRoom === 'ENEMY') {
        nextGrid[session.playerPos.y][session.playerPos.x] = 'EMPTY';
    }

    const isDefeat = !payload.win && !payload.flee;

    if (isDefeat) {
        return handleRetreatManualDungeon({
            ...state,
            knownMercenaries: newKnownMercenaries,
            activeManualDungeon: {
                ...session,
                sessionXp: nextSessionXp,
                encounterStatus: 'DEFEAT'
            }
        });
    }

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        activeManualDungeon: {
            ...session,
            grid: nextGrid,
            collectedLoot: nextCollectedLoot,
            sessionXp: nextSessionXp,
            encounterStatus: payload.win ? 'VICTORY' : (payload.flee ? 'NONE' : 'DEFEAT'),
            isBossDefeated,
            lastActionMessage: payload.win 
                ? `Area neutralized. Squad, catch your breath.`
                : (payload.flee ? `We managed to pull back. Steel yourselves.` : `Everything's gone wrong... we need to get out.`)
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT' || 
                    state.knownMercenaries.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    const mercResults: DungeonResult['mercenaryResults'] = [];

    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            let statusChange: 'NONE' | 'INJURED' | 'DEAD' = 'NONE';

            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.1) { nextStatus = 'DEAD'; statusChange = 'DEAD'; }
                else { 
                    nextStatus = 'INJURED'; statusChange = 'INJURED'; 
                    m.recoveryUntilDay = state.stats.day + 2; 
                }
            } else if (m.currentHp <= 0) {
                nextStatus = 'INJURED'; statusChange = 'INJURED';
                m.recoveryUntilDay = state.stats.day + 1;
            }

            mercResults.push({
                id: m.id, name: m.name, job: m.job, levelBefore: m.level, levelAfter: m.level,
                xpGained: session.sessionXp[m.id] || 0,
                currentXp: m.currentXp, xpToNext: m.xpToNextLevel, statusChange
            });

            return { ...m, status: nextStatus, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        dungeonResult: isDefeat ? {
            dungeonName: dungeon?.name || 'Unknown',
            rewards: session.collectedLoot,
            goldGained: session.goldCollected,
            mercenaryResults: mercResults,
            isDefeat: true
        } : state.dungeonResult,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: The squad has been overwhelmed.' : 'Orderly withdrawal from the zone confirmed.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { 
            ...currentSession, 
            grid: newGrid, 
            npcFound: true, 
            rescuedNpcId: payload.npcId,
            lastActionMessage: `A survivor secured! Let's escort them back to the surface.`
        },
        logs: [`Escorting a survivor out of the depths.`, ...state.logs]
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const tempExpId = `temp_manual_${Date.now()}`;
    const tempExp = {
        id: tempExpId,
        dungeonId: session.dungeonId,
        partyIds: session.partyIds,
        startTime: 0,
        endTime: 0,
        status: 'COMPLETED' as const
    };

    const stateWithTempExp = {
        ...state,
        activeExpeditions: [...state.activeExpeditions, tempExp]
    };

    let newInventory = [...state.inventory];
    session.collectedLoot.forEach(loot => {
        const existing = newInventory.find(i => i.id === loot.id);
        if (existing) {
            newInventory = newInventory.map(i => i.id === loot.id ? { ...i, quantity: i.quantity + loot.count } : i);
        } else {
            const mat = materials[loot.id];
            if (mat) newInventory.push({ ...mat, quantity: loot.count } as InventoryItem);
        }
    });

    const claimedState = handleClaimExpedition({ ...stateWithTempExp, inventory: newInventory }, { 
        expeditionId: tempExpId, 
        rescuedNpcId: session.rescuedNpcId,
        isFullClear: !!session.isBossDefeated
    });

    if (claimedState.dungeonResult) {
        claimedState.dungeonResult.rewards = session.collectedLoot;
        if (session.goldCollected > 0) {
            claimedState.stats.gold += session.goldCollected;
            claimedState.dungeonResult.goldGained = (claimedState.dungeonResult.goldGained || 0) + session.goldCollected;
        }
        claimedState.dungeonResult.mercenaryResults = claimedState.dungeonResult.mercenaryResults.map(res => ({
            ...res,
            xpGained: session.sessionXp[res.id] || res.xpGained
        }));
    }

    return {
        ...claimedState,
        activeManualDungeon: null,
        showManualDungeonOverlay: false
    };
};

