                            ))}
                        </div>
                    )}
                </div>
            </div>
            <div className="p-4 bg-stone-950 text-center border-t border-stone-800">
                <button onClick={onClose} className="w-full py-2 bg-stone-800 hover:bg-stone-700 text-stone-300 font-black uppercase text-[10px] tracking-widest rounded-xl transition-all">Close</button>
            </div>
        </div>
    </div>
);

const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showRetreatConfirm, setShowRetreatConfirm] = useState(false);
    const [showLootOverlay, setShowLootOverlay] = useState(false);
    const [lastMsg, setLastMsg] = useState("");
    const [inspectedMercId, setInspectedMercId] = useState<string | null>(null);
    const [hasInteractedWithNpc, setHasInteractedWithNpc] = useState(false);

    // 함정 밟았는지 확인하기 위한 이전 위치 추적
    const lastPosRef = useRef(session?.playerPos ? { ...session.playerPos } : { x: -1, y: -1 });

    useEffect(() => {
        if (!session) return;

        const { x, y } = session.playerPos;
        const oldPos = lastPosRef.current;

        // 위치가 변경되었을 때만 트랩 체크
        if (x !== oldPos.x || y !== oldPos.y) {
            const currentTile = session.grid[y][x];
            // 함정 방이며 해당 메시지가 함정 발동을 알릴 때 효과 재생
            if (currentTile === 'TRAP' && session.lastActionMessage?.includes('springs')) {
                // 이동이 끝난 후(300ms) 효과 재생
                setTimeout(() => {
                    const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
                    if (scene) scene.playTrapEffect();
                    window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'trap_triggered.mp3' } }));
                }, MOVE_DURATION);
            }
            lastPosRef.current = { x, y };
        }
    }, [session?.playerPos, session?.lastActionMessage]);

    // 골드 및 아이템 획득 상태 추적
    const prevGoldRef = useRef(session?.goldCollected || 0);
    const prevLootRef = useRef<any[]>(session?.collectedLoot || []);

    useEffect(() => {
        if (!session) return;

        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;

        // 1. 골드 획득 처리
        if (session.goldCollected > prevGoldRef.current) {
            const diff = session.goldCollected - prevGoldRef.current;
            // 이동 완료 후 실행
            setTimeout(() => {
                window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'get_coin.mp3' } }));
                if (scene) scene.showFloatingGold(diff);
            }, MOVE_DURATION);
        }
        prevGoldRef.current = session.goldCollected;

        // 2. 아이템 획득 처리 (정밀 대조)
        const currentLoot = session.collectedLoot || [];
        const prevLoot = prevLootRef.current;

        currentLoot.forEach(item => {
            const prevItem = prevLoot.find(p => p.id === item.id);
            const diff = item.count - (prevItem?.count || 0);

            if (diff > 0) {
                // 새로운 아이템이나 수량 증가 발견 -> 이동 완료 후 실행
                setTimeout(() => {
                    window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'found_item.mp3' } }));
                    if (scene) scene.showFloatingItem(item.id, diff);
                }, MOVE_DURATION);
            }
        });

        prevLootRef.current = [...currentLoot.map(i => ({ ...i }))];

    }, [session?.goldCollected, session?.collectedLoot]);

    // --- D-pad & Camera Zoom State ---
    const [dpadTransform, setDpadTransform] = useState(() => {
        const saved = localStorage.getItem('dpad_transform_v2'); 
        let parsed = saved ? JSON.parse(saved) : { x: 0, y: 0, scale: 0.8, opacity: 1.0 };
        if (parsed.scale > 1.2) parsed.scale = 1.2;
        if (parsed.scale < 0.4) parsed.scale = 0.4;
        if (parsed.opacity === undefined) parsed.opacity = 1.0;
        return parsed;
    });
    const [isDraggingDpad, setIsDraggingDpad] = useState(false);
    const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
    const [mapZoom, setMapZoom] = useState(1.0);
    const [showDpadMenu, setShowDpadMenu] = useState(false);

    const rafRef = useRef<number | null>(null);

    const dungeon = useMemo(() => 
        session ? DUNGEONS.find(d => d.id === session.dungeonId) : null,
        [session?.dungeonId]
    );

    const rescueTarget = useMemo(() => {
        if (!dungeon?.rescueMercenaryId) return null;
        return SPECIAL_RECRUITS_REGISTRY[dungeon.rescueMercenaryId] || null;
    }, [dungeon?.rescueMercenaryId]);

    const party = useMemo(() => {
        if (!session) return [];
        return state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    }, [session?.partyIds, state.knownMercenaries]);

    const isEncountered = session?.encounterStatus === 'ENCOUNTERED';
    const isBattle = session?.encounterStatus === 'BATTLE';
    const isStairs = session?.encounterStatus === 'STAIRS';
    const isVictory = session?.encounterStatus === 'VICTORY';
    const currentRoom = session ? session.grid[session.playerPos.y][session.playerPos.x] : null;

    useEffect(() => {
        setHasInteractedWithNpc(false);
    }, [session?.playerPos.x, session?.playerPos.y]);

    useEffect(() => {
        if (isEncountered && currentRoom && (currentRoom === 'ENEMY' || (currentRoom === 'BOSS' && !session.isBossDefeated))) {
            const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;

            // 이동이 끝난 후 조우 연출 시작
            const effectTimer = setTimeout(() => {
                if (scene) scene.playEncounterEffect();
            }, MOVE_DURATION);

            // 전투 시작 타이머도 이동 시간을 고려하여 조정 (2000 -> 2300)
            const combatTimer = setTimeout(() => {
                actions.startCombatManual();
            }, 2000 + MOVE_DURATION); 

            return () => {
                clearTimeout(effectTimer);
                clearTimeout(combatTimer);
            };
        }
    }, [isEncountered, currentRoom, session?.isBossDefeated, actions]);

    const prevIsBattleRef = useRef(false);
    useEffect(() => {
        if (prevIsBattleRef.current && !isBattle) {
            const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) {
                scene.resetEncounterEffect(mapZoom);
            }
        }
        prevIsBattleRef.current = isBattle;
    }, [isBattle, mapZoom]);

    useEffect(() => {
        if (session?.lastActionMessage) {
            setLastMsg(session.lastActionMessage);
        }
    }, [session?.lastActionMessage]);

    useEffect(() => {
        if (!session || !rescueTarget) return;
        if (currentRoom === 'NPC' && !session.npcFound) {
            setLastMsg(`"Help! Please... is someone there? I don't think I can hold out much longer..."`);
        }
    }, [currentRoom, session?.npcFound, rescueTarget]);

    const handleDpadMove = (dx: number, dy: number) => {
        if (isEncountered || isBattle || isStairs) return;
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    const handleDragStart = (e: React.MouseEvent | React.TouchEvent) => {
        setIsDraggingDpad(true);
        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
        setDragStart({ x: clientX - dpadTransform.x, y: clientY - dpadTransform.y });
    };

    const handleDragMove = useCallback((e: MouseEvent | TouchEvent) => {
        if (!isDraggingDpad) return;
        if (rafRef.current) cancelAnimationFrame(rafRef.current);
        rafRef.current = requestAnimationFrame(() => {
            const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
            const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
            setDpadTransform((prev: any) => {
                const nextX = clientX - dragStart.x;
                const nextY = clientY - dragStart.y;
                return { ...prev, x: nextX, y: nextY };
            });
            rafRef.current = null;
        });
    }, [isDraggingDpad, dragStart.x, dragStart.y]);

    const handleDragEnd = useCallback(() => {
        if (isDraggingDpad) {
            setIsDraggingDpad(false);
            if (rafRef.current) {
                cancelAnimationFrame(rafRef.current);
                rafRef.current = null;
            }
            localStorage.setItem('dpad_transform_v2', JSON.stringify(dpadTransform));
        }
    }, [isDraggingDpad, dpadTransform]);

    useEffect(() => {
        if (isDraggingDpad) {
            window.addEventListener('mousemove', handleDragMove, { passive: true });
            window.addEventListener('mouseup', handleDragEnd);
            window.addEventListener('touchmove', handleDragMove, { passive: true });
            window.addEventListener('touchend', handleDragEnd);
        }
        return () => {
            window.removeEventListener('mousemove', handleDragMove);
            window.removeEventListener('mouseup', handleDragEnd);
            window.removeEventListener('touchmove', handleDragMove);
            window.removeEventListener('touchend', handleDragEnd);
        };
    }, [isDraggingDpad, handleDragMove, handleDragEnd]);

    const cycleDpadScale = () => {
        setDpadTransform((prev: any) => {
            let nextScale = prev.scale + 0.2;
            if (nextScale > 1.25) nextScale = 0.4;
            const next = { ...prev, scale: parseFloat(nextScale.toFixed(1)) };
            localStorage.setItem('dpad_transform_v2', JSON.stringify(next));
            return next;
        });
    };

    const handleOpacityChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = parseFloat(e.target.value);
        setDpadTransform((prev: any) => {
            const next = { ...prev, opacity: val };
            localStorage.setItem('dpad_transform_v2', JSON.stringify(next));
            return next;
        });
    };

    const handleZoom = (delta: number) => {
        const nextZoom = Math.min(1.5, Math.max(0.5, mapZoom + delta));
        setMapZoom(nextZoom);
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.updateZoom(nextZoom);
    };

    useEffect(() => {
        if (!isReady || !containerRef.current || !session || !dungeon) return;
        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO, parent: containerRef.current, width: containerRef.current.clientWidth, height: containerRef.current.clientHeight, backgroundColor: 'transparent', transparent: true, scene: [DungeonScene],
                scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
            };
            const game = new Phaser.Game(config);
            gameRef.current = game;
            game.scene.start('DungeonScene', { 
                session, 
                onMove: (dx: number, dy: number) => actions.moveInManualDungeon(dx, dy),
                initialZoom: mapZoom 
            });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) scene.updateSession(session);
        }
    }, [isReady, session, actions, dungeon]);

    useEffect(() => {
        const check = () => { if (containerRef.current?.clientWidth) setIsReady(true); else requestAnimationFrame(check); };
        check();
    }, []);

    if (!session || !dungeon) return null;

    const isOnNPCTile = currentRoom === 'NPC' && !session.npcFound;
    const inspectedMercenary = state.knownMercenaries.find(m => m.id === inspectedMercId) || null;

    const getDialogue = () => {
        if (isOnNPCTile) return { speaker: (rescueTarget?.name || "Survivor"), text: lastMsg };
        if (isEncountered) {
            if (currentRoom === 'BOSS' && session.isBossDefeated) return { speaker: "Inner Voice", text: "The terror is gone, but the air still trembles. We've taken what we came for. Time to leave?" };
            return { speaker: "Inner Voice", text: session.lastActionMessage || lastMsg };
        }
        if (isVictory) return { speaker: "Frontline Shout", text: "They're all down! Sector secured, Lockhart!" };
        if (isStairs) return { speaker: "The Path Ahead", text: lastMsg };
        return { speaker: "Exploration Log", text: lastMsg };
    };

    const { speaker, text: dialogueText } = getDialogue();

    const isEncounterAnimationActive = isEncountered && currentRoom && (currentRoom === 'ENEMY' || (currentRoom === 'BOSS' && !session.isBossDefeated));

    return (
        <div className="fixed inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">
            <div ref={containerRef} className={`absolute inset-0 z-0 transition-opacity ${isBattle ? 'opacity-20 blur-md' : 'opacity-100'}`} />

            {!isBattle && <SquadPanel party={party} onSelectMercenary={(id) => setInspectedMercId(id)} />}

            {/* Top Center: Floor Display */}
            {!isBattle && (
                <div className="absolute top-4 left-1/2 -translate-x-1/2 z-[110] flex items-center gap-3 px-4 py-2 bg-stone-900/90 backdrop-blur-md border border-amber-500/30 rounded-2xl shadow-2xl">
                    <Layers className="w-4 h-4 text-amber-50" />
                    <span className="text-xs md:text-sm font-black text-amber-50 uppercase tracking-widest font-mono">
                        Floor {session.currentFloor} / {session.maxFloors}
                    </span>
                </div>
            )}

            {/* Top Right: Vertical Control Stack */}
            <div className={`absolute top-4 right-4 z-[110] flex flex-col items-end gap-2 pointer-events-auto transition-opacity duration-500 ${isEncounterAnimationActive ? 'opacity-0' : 'opacity-100'}`}>
                <div className={`flex items-center gap-2 px-3 py-1.5 bg-stone-900/80 backdrop-blur-md border rounded-xl shadow-xl transition-all ${session.hasKey ? 'border-amber-500 text-amber-400' : 'border-white/5 text-stone-600 opacity-40'}`}>
                    <Key className={`w-4 h-4 ${session.hasKey ? 'animate-pulse' : ''}`} />
                    <span className="text-[10px] font-black uppercase tracking-widest">{session.hasKey ? 'Key Found' : 'No Key'}</span>
                </div>

                <div className="flex bg-stone-900/80 backdrop-blur-md border border-white/10 rounded-xl overflow-hidden shadow-2xl">
                    <button onClick={() => handleZoom(0.1)} className="p-2.5 hover:bg-stone-800 text-stone-300 transition-colors border-r border-white/5"><Plus className="w-4 h-4" /></button>
                    <div className="flex flex-col items-center justify-center px-2 min-w-[45px] select-none">
                        <span className="text-[8px] font-black text-stone-500 font-bold leading-none">ZOOM</span>
                        <span className="text-[10px] font-mono font-bold text-amber-500">{mapZoom.toFixed(1)}x</span>
                    </div>
                    <button onClick={() => handleZoom(-0.1)} className="p-2.5 hover:bg-stone-800 text-stone-300 transition-colors border-l border-white/5"><Minus className="w-4 h-4" /></button>
                </div>

                <button 
                    onClick={() => setShowRetreatConfirm(true)}
                    className="flex items-center gap-2 px-3 py-2 bg-red-950/40 hover:bg-red-900/60 border border-red-900/30 rounded-xl text-red-500 font-bold text-[10px] uppercase tracking-widest transition-all shadow-xl"
                >
                    <LogOut className="w-4 h-4" /> Retreat
                </button>

                <button 
                    onClick={() => setShowLootOverlay(true)}
                    className="flex items-center gap-2 px-3 py-2 bg-stone-900/80 backdrop-blur-md border border-amber-500/30 rounded-xl shadow-xl text-amber-400 hover:bg-stone-800 transition-all"
                >
                    <Package className="w-4 h-4" />
                    <span className="text-[10px] font-black uppercase tracking-widest">Loot Bag</span>
                </button>
            </div>

            {/* NPC Discovery Scene */}
            {isOnNPCTile && rescueTarget && (
                <div className="absolute inset-0 z-40 flex flex-col items-center justify-end pointer-events-none pb-20">
                    <div className="relative flex justify-center items-end w-full h-[80dvh] animate-in fade-in zoom-in slide-in-from-bottom-12 duration-1000 ease-out">
                        <div className="absolute bottom-[20%] left-1/2 -translate-x-1/2 w-64 h-64 bg-amber-500/20 blur-[80px] rounded-full -z-10 animate-pulse"></div>
                        <div className="absolute bottom-[10%] left-1/2 -translate-x-1/2 w-48 h-10 bg-black/60 blur-2xl rounded-full -z-10"></div>
                        <div className="absolute bottom-[30%] left-1/2 -translate-x-1/2 z-0">
                            <Sparkles className="w-12 h-12 text-amber-300 opacity-40 animate-bounce" />
                        </div>
                        <AnimatedMercenary
                            mercenary={rescueTarget}
                            className="h-full w-auto filter drop-shadow-[0_0_50px_rgba(245,158,11,0.5)] transition-all duration-500 relative z-10"
                        />
                    </div>
                </div>
            )}

            {isBattle && (
                <DungeonCombatView 
                    session={session} party={party} enemies={session.enemies || []} fleeChance={50}
                    onFinish={(win, final) => actions.resolveCombatManual(win, false, final)}
                    onFlee={(final) => actions.resolveCombatManual(false, true, final)}
                />
            )}

            {!isBattle && (
                <>
                    {/* Draggable D-pad Container */}
                    {(!isOnNPCTile || hasInteractedWithNpc) && (
                        <div 
                            className={`pointer-events-auto transition-all z-[200] select-none ${isDraggingDpad ? 'shadow-glow-amber cursor-grabbing' : 'cursor-default'} ${isEncounterAnimationActive ? 'opacity-0 scale-95' : 'opacity-100'}`}
                            style={{
                                position: 'absolute',
                                bottom: 'calc(22dvh + 32px)',
                                right: 16,
                                transform: `translate3d(${dpadTransform.x}px, ${dpadTransform.y}px, 0) scale(${dpadTransform.scale})`,
                                opacity: dpadTransform.opacity,
                                transformOrigin: 'bottom right',
                                willChange: 'transform'
                            }}
                        >
                            <div className="grid grid-cols-3 gap-2 bg-stone-900/90 backdrop-blur-xl p-3 rounded-3xl border border-white/10 shadow-2xl relative">

                                {showDpadMenu && (
                                    <div className="absolute -top-12 right-0 flex items-center gap-3 pointer-events-auto animate-in fade-in slide-in-from-bottom-2 duration-300">
                                        <div className="flex items-center gap-2 bg-stone-900/80 border border-white/10 px-3 py-1.5 rounded-full shadow-lg backdrop-blur-md">
                                            <Ghost className="w-3.5 h-3.5 text-stone-50" />
                                            <input 
                                                type="range" min="0.1" max="1.0" step="0.1"
                                                value={dpadTransform.opacity}
                                                onChange={handleOpacityChange}
                                                className="w-16 h-1 bg-stone-700 rounded-lg appearance-none cursor-pointer accent-amber-500"
                                            />
                                            <span className="text-[8px] font-mono font-bold text-stone-400 w-6">{Math.round(dpadTransform.opacity * 100)}%</span>
                                        </div>

                                        <div className="flex items-center gap-2">
                                            <div 
                                                onMouseDown={handleDragStart} onTouchStart={handleDragStart}
                                                className="w-9 h-9 bg-stone-800 border border-white/20 rounded-full flex items-center justify-center text-blue-400 cursor-grab active:cursor-grabbing hover:bg-stone-700 transition-all shadow-lg active:scale-95"
                                            >
                                                <Move className="w-4 h-4" />
                                            </div>
                                            <button 
                                                onClick={cycleDpadScale}
                                                className="w-9 h-9 bg-stone-800 border border-white/20 rounded-full flex items-center justify-center text-stone-300 hover:text-white transition-all shadow-lg active:scale-90"
                                            >
                                                {dpadTransform.scale >= 1.2 ? <Minimize className="w-4 h-4" /> : <Maximize className="w-4 h-4" />}
                                            </button>
                                        </div>
                                    </div>
                                )}

                                <div />
                                <button onClick={() => handleDpadMove(0,-1)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronUp /></button>

                                <button 
                                    onClick={() => setShowDpadMenu(!showDpadMenu)}
                                    className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${showDpadMenu ? 'bg-amber-600 text-white shadow-glow-amber' : 'bg-stone-800 text-stone-500 hover:text-stone-300'}`}
                                >
                                    <Settings className={`w-6 h-6 ${showDpadMenu ? 'animate-spin-slow' : ''}`} />
                                </button>

                                <button onClick={() => handleDpadMove(-1,0)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronLeft /></button>

                                <div className="w-12 h-12 bg-white/5 rounded-xl flex items-center justify-center text-stone-100/40">
                                    <Zap className="w-6 h-6" />
                                </div>

                                <button onClick={() => handleDpadMove(1,0)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronRight /></button>

                                <div />
                                <button onClick={() => handleDpadMove(0,1)} className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-white active:bg-stone-700 shadow-lg"><ChevronDown /></button>
                                <div />
                            </div>
                        </div>
                    )}

                    {/* Bottom dialogue box container */}
                    <div className="absolute bottom-4 left-1/2 -translate-x-1/2 w-[95vw] max-w-5xl z-50 pointer-events-none">
                        <div className={`flex flex-col items-end gap-4 relative transition-all duration-500 ${isEncounterAnimationActive ? 'opacity-0 translate-y-8' : 'opacity-100 translate-y-0'}`}>
                            <DialogueBox 
                                speaker={speaker}
                                speakerAvatar={isOnNPCTile ? getAssetUrl(rescueTarget?.profileImage || 'default.png', 'mercenaries') : undefined}
                                text={dialogueText}
                                options={isOnNPCTile ? [
                                    { label: "GET THEM TO SAFETY", action: () => { 
                                        if (dungeon?.rescueMercenaryId) {
                                            actions.rescueMercenary(dungeon.rescueMercenaryId); 
                                            actions.showToast(`${rescueTarget?.name} has been secured!`); 
                                        }
                                    }, variant: 'primary' as const },
                                    { label: "WE'LL BE BACK FOR YOU", action: () => {
                                        setLastMsg("We've marked the spot. Resuming exploration for now.");
                                        setHasInteractedWithNpc(true);
                                    }, variant: 'neutral' as const }
                                ] : isEncountered ? [
                                    ...(currentRoom === 'BOSS' && session.isBossDefeated ? [
                                        { label: "CLAIM THE LOOT AND LEAVE", action: () => actions.finishManualAssault(), variant: 'primary' as const },
                                        { label: "CONTINUE EXPLORING", action: () => actions.resolveCombatManual(false, true, party), variant: 'neutral' as const }
                                    ] : [])
                                ] : isStairs ? [
                                    { label: `INTO THE ABYSS (Sector ${session.currentFloor + 1})`, action: () => actions.proceedToNextFloorManual(), variant: 'primary' as const },
                                    { label: "REACH THE SURFACE", action: () => actions.finishManualAssault(), variant: 'primary' as const },
                                    { label: "STAY IN THIS SECTOR", action: () => actions.resolveCombatManual(false, true, party), variant: 'neutral' as const }
                                ] : isVictory ? [
                                    { label: "RESUME SEARCH", action: () => actions.resolveCombatManual(false, true, party), variant: 'primary' as const }
                                ] : currentRoom === 'ENTRANCE' && session.isBossDefeated ? [
                                    { label: "END MISSION", action: () => actions.finishManualAssault(), variant: 'primary' as const }
                                ] : []}
                                className="w-full pointer-events-auto"
                            />
                        </div>
                    </div>
                </>
            )}

            {inspectedMercenary && (
                <MercenaryDetailModal 
                    mercenary={inspectedMercenary}
                    onClose={() => setInspectedMercId(null)}
                    onUnequip={(mercId, slot) => actions.unequipItem(mercId, slot)}
                    isReadOnly={false} 
                />
            )}

            {showLootOverlay && (
                <LootOverlay 
                    loot={session.collectedLoot} 
                    gold={session.goldCollected} 
                    onClose={() => setShowLootOverlay(false)} 
                />
            )}

            <ConfirmationModal isOpen={showRetreatConfirm} title="Abort Mission?" message="Extraction will return the squad to safety. No rewards will be collected." onConfirm={() => actions.retreatFromManualDungeon()} onCancel={() => setShowRetreatConfirm(false)} isDanger={true} />
        </div>
    );
};

export default AssaultNavigator;

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { User, ChevronRight, Coins, Package, Lock } from 'lucide-react';
import { useGame } from '../context/GameContext';
import { materials } from '../data/materials';
import { getAssetUrl } from '../utils';

interface DialogueOption {
  label: string;
  action: () => void;
  variant?: 'primary' | 'danger' | 'neutral';
  disabled?: boolean;
}

interface ItemDetail {
  id: string;
  image?: string; // 추가: 실제 이미지 파일명
  icon: string;
  price: number;
  requirements?: { id: string; count: number }[];
  isUnlocked?: boolean;
}

interface DialogueBoxProps {
  speaker: string;
  text: string;
  options?: DialogueOption[];
  highlightTerm?: string;
  itemDetail?: ItemDetail;
  className?: string;
  speakerAvatar?: string;
}

const DialogueBox: React.FC<DialogueBoxProps> = ({ 
  speaker, 
  text, 
  options = [], 
  highlightTerm,
  itemDetail,
  className = "relative w-full z-40",
  speakerAvatar
}) => {
  const { state } = useGame();
  const [displayedIndex, setDisplayedIndex] = useState(0);
  const [isTyping, setIsTyping] = useState(false);
  const [showItemTooltip, setShowItemTooltip] = useState(false);
  const [tooltipCoords, setTooltipCoords] = useState({ x: 0, y: 0 });
  const [imgError, setImgError] = useState(false);

  const isMounted = useRef(true);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const textContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (textContainerRef.current) {
      const container = textContainerRef.current;
      const scrollHandle = requestAnimationFrame(() => {
        container.scrollTop = container.scrollHeight;
      });
      return () => cancelAnimationFrame(scrollHandle);
    }
  }, [displayedIndex, text, isTyping]);

  useEffect(() => {
    if (timerRef.current) clearInterval(timerRef.current);

    setDisplayedIndex(0);
    setIsTyping(true);
    setShowItemTooltip(false);
    setImgError(false);
    let index = 0;
    const speed = 25; 

    timerRef.current = setInterval(() => {
      if (!isMounted.current) return;

      index++;
      if (index > text.length) {
        if (timerRef.current) clearInterval(timerRef.current);
        setIsTyping(false);
        setDisplayedIndex(text.length);
      } else {
        setDisplayedIndex(index);
      }
    }, speed);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [text]);

  const playClickSfx = () => {
      window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'item_click.mp3' } }));
  };

  const handleSkipTyping = () => {
    if (isTyping) {
      if (timerRef.current) clearInterval(timerRef.current);
      setDisplayedIndex(text.length);
      setIsTyping(false);
      playClickSfx();
    }
  };

  const getInventoryCount = (id: string) => {
    return state.inventory.find(i => i.id === id)?.quantity || 0;
  };

  const updateTooltipPosition = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    setTooltipCoords({
      x: rect.left + rect.width / 2,
      y: rect.top
    });
  };

  const renderFormattedText = () => {
    if (!highlightTerm) {
      return <span>{text.slice(0, displayedIndex)}</span>;
    }

    const parts = text.split(new RegExp(`(${highlightTerm})`, 'g'));
    let charCount = 0;

    return parts.map((part, i) => {
      const startChar = charCount;
      const endChar = charCount + part.length;
      charCount = endChar;

      const visibleCountInPart = Math.max(0, Math.min(part.length, displayedIndex - startChar));
      if (visibleCountInPart <= 0) return null;

      const visiblePart = part.slice(0, visibleCountInPart);

      if (part === highlightTerm) {
        return (
          <span 
            key={i} 
            className="text-amber-400 font-black underline decoration-amber-500/50 underline-offset-4 cursor-pointer relative inline-block pointer-events-auto"
            onClick={(e) => { 
                e.stopPropagation(); 
                updateTooltipPosition(e); 
                setShowItemTooltip(!showItemTooltip); 
                playClickSfx();
            }}
          >
            {visiblePart}
          </span>
        );
      }

      return <React.Fragment key={i}>{visiblePart}</React.Fragment>;
    });
  };

  const tooltipElement = showItemTooltip && itemDetail && createPortal(
    <div 
      className="fixed z-[10000] pointer-events-none p-3 md:p-4 bg-stone-900/98 backdrop-blur-2xl border-2 border-stone-700 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.9)] w-[80vw] max-w-[240px] md:max-w-[320px] animate-in fade-in zoom-in-95 duration-200"
      style={{ 
        left: `${Math.max(130, Math.min(window.innerWidth - 130, tooltipCoords.x))}px`, 
        top: `${tooltipCoords.y - 10}px`,
        transform: 'translate(-50%, -100%)'
      }}
    >
      <div className="flex items-center gap-3 mb-2 md:mb-3 pb-2 md:pb-3 border-b border-white/10">
        <div className={`w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-xl border-2 flex items-center justify-center shadow-inner shrink-0 overflow-hidden ${!itemDetail.isUnlocked ? 'border-amber-600/50' : 'border-stone-800'}`}>
          {!itemDetail.isUnlocked ? (
            <span className="text-2xl md:text-4xl font-serif text-amber-500 font-black animate-pulse">?</span>
          ) : (
            <>
              {!imgError ? (
                <img 
                  src={getAssetUrl(itemDetail.image || `${itemDetail.id}.png`, 'equipments')} 
                  onError={(e) => {
                    console.error('[Tooltip Debug] Image Failed to Load:', (e.target as HTMLImageElement).src);
                    setImgError(true);
                  }}
                  className="w-7 h-7 md:w-11 md:h-11 object-contain" 
                  alt="item" 
                />
              ) : (
                <span className="text-xl md:text-3xl">{itemDetail.icon}</span>
              )}
            </>
          )}
        </div>
        <div className="flex flex-col leading-none">
          <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase tracking-widest mb-1">Price</span>
          <div className={`flex items-center gap-1 font-mono font-black text-xs md:text-xl ${!itemDetail.isUnlocked ? 'text-stone-600' : 'text-emerald-400'}`}>
            <Coins className="w-3 h-3 md:w-5 md:h-5" />
            {!itemDetail.isUnlocked ? '???,???' : itemDetail.price.toLocaleString()} G
          </div>
        </div>
      </div>

      <div className="space-y-2">
        <h5 className="text-[7px] md:text-[9px] font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5">
          <Package className="w-2 h-2 md:w-3 md:h-3" /> Required Materials
        </h5>

        <div className="grid gap-1">
          {itemDetail.requirements && itemDetail.requirements.length > 0 ? (
            itemDetail.requirements.map((req, idx) => {
              const isClue = idx === 0; 
              const shouldShow = itemDetail.isUnlocked || isClue;

              if (!shouldShow) {
                return (
                  <div key={req.id} className="flex justify-between items-center text-[8px] md:text-xs opacity-40">
                    <span className="truncate mr-2 font-bold tracking-tight text-stone-600">
                      ???
                    </span>
                    <div className="flex items-center gap-1 shrink-0">
                      <span className="font-mono font-black text-stone-700">
                        ? / ?
                      </span>
                      <div className="w-1 h-1 rounded-full bg-stone-800" />
                    </div>
                  </div>
                );
              }

              const hasCount = getInventoryCount(req.id);
              const isEnough = hasCount >= req.count;
              const mat = Object.values(materials).find(m => m.id === req.id);

              return (
                <div key={req.id} className="flex justify-between items-center text-[8px] md:text-xs">
                  <span className={`truncate mr-2 font-bold tracking-tight ${isEnough ? 'text-stone-300' : 'text-red-400'}`}>
                    {mat?.name || req.id}
                  </span>
                  <div className="flex items-center gap-1 shrink-0">
                    <span className={`font-mono font-black ${isEnough ? 'text-stone-500' : 'text-red-500'}`}>
                      {hasCount}/{req.count}
                    </span>
                    <div className={`w-1 h-1 rounded-full ${isEnough ? 'bg-emerald-500 shadow-[0_0_4px_rgba(16,185,129,0.5)]' : 'bg-red-500 animate-pulse'}`} />
                  </div>
                </div>
              );
            })
          ) : (
            <div className="text-[8px] md:text-xs text-stone-600 italic">No specific requirements found.</div>
          )}
        </div>

        {!itemDetail.isUnlocked && (
          <div className="mt-2 pt-2 border-t border-white/5 flex flex-col items-center text-center">
            <div className="flex items-center gap-1.5 text-amber-600/80">
              <Lock className="w-2.5 h-2.5 md:w-3 md:h-3" />
              <span className="text-[6px] md:text-[8px] font-black uppercase tracking-widest">Locked Knowledge</span>
            </div>
          </div>
        )}
      </div>

      <div className="absolute top-full left-1/2 -translate-x-1/2 w-0 h-0 border-l-[8px] md:border-l-[12px] border-l-transparent border-r-[8px] md:border-r-[12px] border-r-transparent border-t-[8px] md:border-t-[12px] border-t-stone-900/98"></div>
    </div>,
    document.body
  );

  return (
    <div className={className} onClick={() => { if (showItemTooltip) { setShowItemTooltip(false); playClickSfx(); } }}>
      {tooltipElement}

      <div 
        className="w-full h-[22dvh] min-h-[120px] md:h-[28vh] md:min-h-[160px] bg-stone-950/25 backdrop-blur-3xl border border-white/10 md:border-2 rounded-2xl md:rounded-3xl shadow-[0_25px_70px_rgba(0,0,0,0.7)] flex flex-row overflow-hidden animate-in slide-in-from-bottom-8 fade-in duration-500 ring-1 ring-white/10"
      >
        <div className="bg-stone-900/20 p-2 md:p-6 border-r border-white/5 flex flex-col items-center gap-1 md:gap-4 w-20 md:w-48 shrink-0 justify-center">
          <div className="w-9 h-9 md:w-20 md:h-20 rounded-full bg-gradient-to-br from-amber-900/30 to-stone-800/40 border border-amber-600/30 flex items-center justify-center shadow-inner ring-1 ring-white/5 overflow-hidden">
             {speakerAvatar ? (
               <img src={speakerAvatar} className="w-full h-full object-cover" alt={speaker} />
             ) : (
               <User className="w-5 h-5 md:w-10 md:h-10 text-amber-500/90 drop-shadow-[0_0_15px_rgba(245,158,11,0.5)]" />
             )}
          </div>
          <div className="flex flex-col items-center overflow-hidden w-full">
              <span className="font-black text-amber-50 text-[10px] md:text-xl text-center font-serif leading-tight tracking-tight drop-shadow-md truncate w-full px-1">
                {speaker}
              </span>
          </div>
        </div>

        <div 
          className="flex-1 p-2.5 md:p-8 relative flex flex-col min-h-0 bg-gradient-to-br from-white/5 to-transparent cursor-pointer"
          onClick={handleSkipTyping}
        >
          <div 
            ref={textContainerRef}
            className={`flex-1 overflow-y-auto overflow-x-hidden custom-scrollbar pr-1 md:pr-2 mb-1 md:mb-2 min-h-0 ${isTyping ? 'typing-active' : ''}`}
            style={{ scrollBehavior: isTyping ? 'auto' : 'smooth' }}
          >
            <div 
              className="text-stone-50 leading-snug md:leading-relaxed font-medium drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)] transition-opacity duration-300 break-words whitespace-pre-wrap"
              style={{ fontSize: 'clamp(0.9rem, 2.4dvh, 1.6rem)' }}
            >
              {renderFormattedText()}
            </div>
          </div>

          {!isTyping && options.length > 0 && (
            <div className="mt-auto pt-2 flex flex-wrap gap-1.5 md:gap-4 justify-end animate-in fade-in slide-in-from-right-4 pb-1 shrink-0">
              {options.map((option, idx) => (
                <button
                  key={idx}
                  onClick={(e) => { e.stopPropagation(); playClickSfx(); option.action(); }}
                  disabled={option.disabled}
                  className={`px-4 md:px-10 py-1.5 md:py-4 rounded-lg md:rounded-xl font-black text-[9px] md:text-sm flex items-center gap-1.5 md:gap-3 transition-all transform active:scale-95 border shadow-2xl ${
                    option.disabled 
                      ? 'bg-stone-800/40 text-stone-600 border-stone-700/30 cursor-not-allowed'
                      : option.variant === 'danger'
                        ? 'bg-red-900/60 text-red-50 border-red-800/50 hover:bg-red-700 hover:border-red-400'
                        : option.variant === 'neutral'
                            ? 'bg-stone-800/60 text-stone-100 border-stone-600 hover:bg-stone-750 hover:border-stone-400'
                            : 'bg-amber-700/80 text-white border-amber-500 hover:bg-amber-600 hover:border-amber-300 hover:shadow-amber-900/60'
                  }`}
                >
                  <span className="whitespace-nowrap">{option.label}</span>
                  {!option.disabled && <ChevronRight className="hidden xs:block w-2.5 md:w-5 h-2.5 md:h-5 opacity-70 group-hover:translate-x-1 transition-transform" />}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default DialogueBox;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { ArrowLeft, Heart, Gift, MessageSquare, UserPlus, Package, X, Star, Wrench, Search, UserMinus, Ban, Lock, Unlock, Sword, Shield, ChevronUp } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { Mercenary } from '../../../models/Mercenary';
import { CONTRACT_CONFIG, calculateHiringCost } from '../../../config/contract-config';
import { InventoryItem, EquipmentSlotType } from '../../../types/inventory';
import { MercenaryDetailModal } from '../../modals/MercenaryDetailModal';
import { ItemSelectorList } from '../../ItemSelectorList';
import { AnimatedMercenary } from '../../common/ui/AnimatedMercenary';
import { MercenaryPortrait } from '../../common/ui/MercenaryPortrait';

interface TavernInteractionProps {
    mercenary: Mercenary;
    onBack: () => void;
}

interface FloatingHeart {
    id: number;
    left: number;
    delay: number;
    size: number;
}

type InteractionStep = 'IDLE' | 'CONFIRM_HIRE' | 'CONFIRM_FIRE';

const TavernInteraction: React.FC<TavernInteractionProps> = ({ mercenary, onBack }) => {
    const { state, actions } = useGame();
    const [dialogue, setDialogue] = useState(`(You sit across from ${mercenary.name}.)`);
    const [showGiftMenu, setShowGiftMenu] = useState(false);
    const [showDetail, setShowDetail] = useState(false);
    const [pendingGiftItem, setPendingGiftItem] = useState<InventoryItem | null>(null);
    const [floatingHearts, setFloatingHearts] = useState<FloatingHeart[]>([]);
    const [step, setStep] = useState<InteractionStep>('IDLE');
    const isHired = mercenary.status === 'HIRED' || mercenary.status === 'ON_EXPEDITION' || mercenary.status === 'INJURED';
    const isOnExpedition = mercenary.status === 'ON_EXPEDITION';
    const hiringCost = calculateHiringCost(mercenary.level, mercenary.job);
    const canAfford = state.stats.gold >= hiringCost;
    const hasAffinity = mercenary.affinity >= CONTRACT_CONFIG.HIRE_AFFINITY_THRESHOLD;
    const hasUnallocated = isHired && (mercenary.bonusStatPoints || 0) > 0;

    const playClick = useCallback(() => {
        window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'item_click.mp3' } }));
    }, []);

    const handleTalk = () => {
        if (pendingGiftItem || step !== 'IDLE') return;
        playClick();

        if (!state.talkedToToday.includes(mercenary.id)) {
            actions.talkMercenary(mercenary.id);
            const newHearts = Array.from({ length: 5 }).map((_, i) => ({
                id: Date.now() + i,
                left: 40 + Math.random() * 20,
                delay: Math.random() * 0.5,
                size: 16 + Math.random() * 12
            }));
            setFloatingHearts(prev => [...prev, ...newHearts]);
            setTimeout(() => setFloatingHearts([]), 3000);
        }

        const lines = [
            "The road is long, but a warm fire makes it easier.",
            "I heard rumors of rare ores in the Rat Cellar...",
            "What's your specialty, smith? I need something that won't break.",
            "Business seems slow today. Maybe I can help with that later.",
            "I've seen many forges, but yours has... potential.",
            "Tell me, do you have any ale left?",
            "I'm looking for work. Something that pays in gold and glory."
        ];
        setDialogue(lines[Math.floor(Math.random() * lines.length)]);
    };

    const handleRecruitInit = () => {
        playClick();
        if (!hasAffinity) {
            setDialogue("I don't know you well enough to pledge my blade to your forge yet.");
            return;
        }
        if (!canAfford) {
            setDialogue(`The contract is ${hiringCost} gold. Come back when you have the coin.`);
            return;
        }
        setStep('CONFIRM_HIRE');
        setDialogue(`"A contract for ${hiringCost} Gold? Are you certain you want me on your squad?"`);
    };

    const handleConfirmHire = () => {
        actions.hireMercenary(mercenary.id, hiringCost);
        setStep('IDLE');
        setDialogue("A fair contract. My strength is yours, Lockhart.");
    };

    const handleTerminateInit = () => {
        playClick();
        setStep('CONFIRM_FIRE');
        setDialogue(`(Surprised) "Terminate the contract? Did I fail you in some way? If you let me go now, I might not return for some time."`);
    };

    const handleConfirmTerminate = () => {
        actions.fireMercenary(mercenary.id);
        setStep('IDLE');
        setDialogue(`"I see. Perhaps our paths will cross again on another road. Farewell, smith."`);
    };

    const handleRecall = () => {
        if (mercenary.assignedExpeditionId) {
            playClick();
            if (window.confirm("Abort current mission and recall the entire squad? No rewards will be gained.")) {
                actions.abortExpedition(mercenary.assignedExpeditionId);
                setDialogue("(Heavy breathing) We're back. The mission was too hazardous... we had to retreat.");
            }
        }
    };

    const handleCancelStep = () => {
        setStep('IDLE');
        setDialogue(`"I'm glad we cleared that up."`);
    };

    const handleSelectItemForGift = (item: InventoryItem) => {
        if (item.isLocked) {
            actions.showToast("Cannot gift locked items.");
            return;
        }
        playClick();
        setPendingGiftItem(item);
        setShowGiftMenu(false);
        const raritySuffix = item.type === 'EQUIPMENT' ? ` (${item.equipmentData?.rarity})` : '';
        setDialogue(`(You hold out the ${item.name}${raritySuffix}.) "Would you like this?"`);
    };

    const handleConfirmGift = () => {
        if (!pendingGiftItem) return;
        const item = pendingGiftItem;
        actions.giveGift(mercenary.id, item.id);

        if (item.type === 'EQUIPMENT' && item.equipmentData) {
            const q = item.equipmentData.quality;
            if (q > 100) {
                setDialogue(`(Eyes widening) "Is this for me? A masterpiece like this? I... I am truly honored, Lockhart. I will carry it with my life."`);
            } else if (q < 80) {
                setDialogue(`"A gift? I appreciate the gesture, but... this ${item.name} looks a bit worse for wear. I hope your anvil finds its true rhythm soon."`);
            } else {
                setDialogue(`(Surprised) "Is this for me? A ${item.name}? I will carry it with honor."`);
            }
        } else {
            setDialogue(`${mercenary.name} seems pleased with the gift. "For me? You're too kind."`);
        }
        setPendingGiftItem(null);
    };

    const handleCancelGift = () => {
        setPendingGiftItem(null);
        setDialogue(`(You pull your hand back.) "Actually, never mind."`);
    };

    const handleShowDetail = () => {
        playClick();
        setShowDetail(true);
    };

    const handleBack = () => {
        playClick();
        onBack();
    };

    // Filter restricted to Mercenary's interests
    const giftableItems = state.inventory.filter(i => 
        ['EQUIPMENT', 'PRODUCT', 'CONSUMABLE', 'GIFT'].includes(i.type)
    );

    return (
        <div className="fixed inset-0 z-[1000] bg-stone-950 overflow-hidden flex flex-col items-center justify-center">

            <style>
                {`
                    @keyframes heartFloatUp {
                        0% { transform: translateY(0) translateX(0) scale(0.5); opacity: 0; }
                        20% { opacity: 1; }
                        100% { transform: translateY(-300px) translateX(var(--wobble)) scale(1.2); opacity: 0; }
                    }
                    .animate-heart {
                        animation: heartFloatUp 2.5s ease-out forwards;
                    }
                `}
            </style>

            <div className="absolute inset-0 z-0">
                <img 
                    src={getAssetUrl('tavern_bg.jpeg', 'bg')} 
                    alt="Tavern Interior" 
                    className="absolute inset-0 w-full h-full object-cover opacity-50"
                />
                <div className="absolute inset-0 bg-black/40"></div>
            </div>

            <button 
                onClick={handleBack}
                className="absolute top-4 left-4 z-[1050] flex items-center gap-2 px-4 py-2 bg-stone-900/80 hover:bg-red-900/60 text-stone-300 hover:text-red-100 rounded-xl border border-stone-700 backdrop-blur-md transition-all shadow-2xl active:scale-90 group"
                title="Leave Interaction"
            >
                <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
                <span className="text-xs font-black uppercase tracking-widest">Back</span>
            </button>

            <div className="absolute top-20 left-4 z-40 animate-in slide-in-from-left-4 duration-500 w-[32%] max-w-[180px] md:max-w-[240px]">
                <div className="bg-stone-900/90 border border-stone-700 p-2.5 md:p-4 rounded-xl backdrop-blur-md shadow-2xl">
                    <div className="flex justify-between items-center mb-1.5 md:mb-2.5">
                        <div className="flex items-center gap-2 min-w-0">
                            <MercenaryPortrait mercenary={mercenary} className="w-7 h-7 md:w-9 md:h-9 rounded-lg border border-white/10 shrink-0" />
                            <div className="flex flex-col leading-tight min-w-0">
                                <span className="font-black text-amber-50 text-[8px] md:text-[10px] tracking-widest uppercase truncate">{mercenary.job}</span>
                                <span className="text-stone-500 text-[8px] md:text-[10px] font-mono">Lv.{mercenary.level}</span>
                            </div>
                        </div>
                        <div className="flex items-center gap-1 text-pink-400 font-bold bg-pink-950/20 px-1 md:px-1.5 py-0.5 rounded border border-pink-900/30 shrink-0">
                            <Heart className="w-2.5 h-2.5 md:w-3.5 md:h-3.5 fill-pink-400" />
                            <span className="font-mono text-[9px] md:text-xs">{mercenary.affinity}</span>
                        </div>
                    </div>

                    <div className="space-y-1.5 md:space-y-2.5">
                        <div className="flex flex-col gap-0.5">
                            <div className="flex justify-between items-center text-[7px] md:text-[9px] font-mono text-stone-500 px-0.5">
                                <span>HP</span>
                                <span>{Math.floor(mercenary.currentHp)}/{mercenary.maxHp}</span>
                            </div>
                            <div className="w-full bg-stone-950 h-1 md:h-1.5 rounded-full overflow-hidden border border-stone-800">
